INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-11', E'남겨진 남유다 백성의 행동 (예레미야 43장)', E'예레미야 43장', E'바벨론에 의해 예루살렘이 멸망한 후, 남은 백성들은 여전히 하나님의 음성에 귀 기울이지 않습니다. 예레미야가 전한 하나님의 말씀은 분명했습니다. 유다 땅에 머물며 바벨론의 통치를 받아들이라는 것이었습니다. 그러나 호사야의 아들 아사랴와 가레아의 아들 요하난을 비롯한 지도자들은 예레미야의 메시지를 거짓으로 단정하며, 오히려 바룩이 예레미야를 부추겨 백성들을 바벨론에 넘기려 한다고 모함합니다.\n\n결국 남은 백성들은 하나님의 명령을 어기고 애굽으로 도피합니다. 그들은 남녀노소와 왕의 딸들, 그리고 예레미야와 바룩까지 강제로 데리고 애굽의 다바네스로 갔습니다. 예루살렘의 멸망이라는 엄청난 심판을 목도하고도 여전히 하나님의 뜻을 거역하는 백성들의 모습은 인간의 완고함이 얼마나 깊은지를 보여줍니다.\n\n다바네스에 도착한 후에도 하나님의 말씀은 멈추지 않습니다. 하나님께서는 예레미야에게 상징적 행동을 명하십니다. 바로의 궁전 입구에 큰 돌들을 묻으라는 것이었습니다. 이 돌들은 장차 바벨론 왕 느부갓네살이 애굽을 침공할 때 그의 보좌가 놓일 자리를 예표합니다. 애굽으로 도피한 백성들이 안전할 것이라 믿었던 그곳마저 바벨론의 손에 넘어갈 것이라는 예언입니다.\n\n하나님께서는 느부갓네살을 "내 종"이라 부르시며, 그가 애굽의 신전들을 불사르고 석상들을 깨뜨릴 것을 선포하십니다. 목자가 옷을 두르듯 애굽 땅을 정복할 것이라는 표현은 바벨론의 완전한 승리를 암시합니다. 백성들이 의지하려 했던 애굽의 군사력과 신들조차 하나님의 심판 앞에서는 무력할 수밖에 없음을 보여주는 것입니다.', E'오늘의 핵심\n하나님의 분명한 말씀에도 불구하고 남은 백성들은 애굽으로 도피하지만, 그곳조차 하나님의 심판이 미칠 것임을 예레미야의 상징적 행동을 통해 선포하십니다.\n\n묵상 질문\n1. 내가 하나님의 말씀보다 더 의지하고 있는 ''애굽''은 무엇인가요?\n2. 반복되는 불순종에도 계속 말씀하시는 하나님의 마음을 어떻게 이해할 수 있을까요?\n3. 오늘 나에게 주신 하나님의 분명한 말씀에 순종하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-12', E'남겨진 남유다 백성의 행동 (예레미야 44장)', E'예레미야 44장', E'애굽으로 피난한 유다 백성에게 하나님의 말씀이 예레미야를 통해 다시 선포됩니다. 그들은 바벨론의 침공을 피해 믹돌과 다바네스, 놉과 바드로스 지방에 흩어져 살고 있었습니다. 하나님께서는 예루살렘과 유다 성읍들이 황무지가 된 이유를 다시 한 번 상기시키십니다. 그것은 백성들이 알지 못하는 다른 신들에게 분향하고 섬겼기 때문이었습니다. 하나님께서는 끊임없이 선지자들을 보내어 경고하셨지만, 백성들은 듣지 않았고 악에서 돌이키지 않았습니다.\n\n놀랍게도 애굽 땅에 도착한 유다 백성들은 여전히 우상숭배를 계속하고 있었습니다. 그들은 "하늘의 여왕"에게 분향하며 전제를 드리는 일을 멈추지 않았습니다. 더욱 충격적인 것은 그들의 주장입니다. "우리가 하늘의 여왕에게 분향할 때는 먹을 것이 풍부하고 복을 받았는데, 그것을 폐한 후부터 모든 것이 궁핍하고 칼과 기근에 멸망을 당했다"고 말합니다. 그들은 예루살렘의 멸망 원인을 완전히 거꾸로 이해하고 있었던 것입니다.\n\n예레미야는 하나님의 심판이 임한 진짜 이유를 분명히 밝힙니다. 바로 그들이 하늘의 여왕에게 분향하고 여호와의 율법을 따르지 않았기 때문입니다. 하나님께서는 애굽 땅의 유다 백성들에게도 동일한 심판을 선언하십니다. 그들은 칼과 기근으로 멸망할 것이며, 소수를 제외하고는 유다 땅으로 돌아오지 못할 것입니다. 특히 하나님께서는 "애굽 온 땅에 사는 유다 사람들의 입에서 다시는 내 이름을 부르며 맹세하는 자가 없으리라"고 선언하심으로써, 그들이 하나님의 백성으로서의 정체성을 상실하게 될 것임을 암시하십니다.\n\n이 말씀은 오늘 우리에게도 경각심을 줍니다. 고난의 원인을 잘못 진단하고 오히려 죄악을 정당화하는 어리석음에 빠지지 않도록 주의해야 합니다. 참된 복의 근원은 하나님께 있으며, 그분의 말씀에 순종하는 것이 생명의 길임을 기억해야 합니다.', E'오늘의 핵심\n애굽으로 피난한 유다 백성들은 예루살렘 멸망의 교훈을 깨닫지 못하고 여전히 우상숭배를 계속하며, 오히려 그것을 복의 근원으로 착각하는 영적 무지를 보여줍니다.\n\n묵상 질문\n1. 내가 고난의 원인을 잘못 해석하고 오히려 죄를 정당화한 적은 없나요?\n2. 참된 복의 근원을 세상의 것에서 찾고 있지는 않은지 돌아보셨나요?\n3. 하나님의 경고를 듣고도 계속 고집하고 있는 영역이 있다면 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-14', E'열방에 대한 심판 (예레미야 46장)', E'예레미야 46장', E'열방에 대한 하나님의 심판 메시지가 예레미야를 통해 선포되기 시작합니다. 그 첫 대상은 애굽입니다. 유다 왕국이 바벨론의 위협 앞에서 의지하려 했던 애굽의 운명은 이미 갈그미스 전투에서 결정되었습니다. 주전 605년, 유브라데 강 가에서 바로느고의 군대는 느부갓네살에게 참패를 당했고, 이는 근동 지역의 패권이 애굽에서 바벨론으로 완전히 넘어가는 역사적 전환점이 되었습니다.\n\n예레미야가 전하는 애굽의 모습은 나일 강이 범람하듯 교만하게 일어나 온 땅을 덮으려 했던 제국의 허망한 최후입니다. "내가 일어나 땅을 덮어 성읍들과 그 주민을 멸할 것이라"(렘 46:8)고 호언장담했던 애굽이지만, 하나님의 심판 앞에서는 아무런 힘을 발휘할 수 없었습니다. 구스와 붓과 루딤의 용사들, 최정예 부대와 첨단 무기로 무장했어도 하나님께서 정하신 심판의 날을 피할 수는 없었습니다.\n\n애굽을 향한 하나님의 심판은 단순한 역사적 사건이 아닙니다. 이는 하나님을 떠나 인간의 힘과 지혜를 의지했던 모든 이들에게 주시는 경고의 메시지입니다. 애굽의 몰락은 하나님 아닌 그 어떤 것도 우리의 참된 피난처가 될 수 없음을 보여줍니다. 길르앗의 유향으로도, 그 어떤 치료법으로도 하나님의 심판으로 인한 상처는 치유될 수 없었습니다.\n\n그러나 이 심판의 메시지 가운데서도 하나님은 놀라운 위로의 말씀을 주십니다. "내 종 야곱아 두려워하지 말라"는 음성이 심판의 소용돌이 속에서도 울려 퍼집니다. 포로로 끌려간 이스라엘 백성을 구원하시고, 다시 평안한 삶으로 인도하시겠다는 약속입니다. 열방을 심판하시는 하나님은 동시에 자기 백성을 끝까지 지키시는 신실한 하나님이십니다. 비록 징계는 있을지라도 멸망시키지는 않으시며, 법도대로 다스리시되 언약의 사랑은 변치 않으십니다.', E'오늘의 핵심\n애굽의 몰락은 하나님 외에는 그 어떤 강대국도 우리의 참된 도움이 될 수 없음을 보여주며, 심판 중에도 자기 백성을 향한 하나님의 신실한 사랑은 변하지 않습니다.\n\n묵상 질문\n1. 오늘날 내가 하나님보다 더 의지하고 있는 ''애굽''은 무엇입니까?\n2. 위기의 때에 세상의 힘을 의지하려는 유혹을 어떻게 극복할 수 있을까요?\n3. "두려워하지 말라"는 하나님의 위로가 내 삶의 어떤 상황에 필요합니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-15', E'열방에 대한 심판 (예레미야 47장)', E'예레미야 47장', E'블레셋은 이스라엘과 가장 가까이에서 오랜 시간 대립관계에 있던 민족이었습니다. 사사 시대부터 다윗 왕국에 이르기까지 이스라엘을 끊임없이 괴롭혔던 이들에게 이제 하나님의 심판이 선포됩니다. 예레미야는 북쪽에서 밀려오는 물결처럼 바벨론 군대가 블레셋 전 지역을 휩쓸 것을 예언합니다. 이 심판의 물결은 너무나 압도적이어서 아버지들조차 자녀를 돌보지 못할 정도로 무력해질 것이라고 묘사됩니다.\n\n블레셋의 주요 도시들인 가사와 아스글론이 대머리가 되고 잠잠하게 된다는 표현은 완전한 황폐화를 의미합니다. 특히 블레셋이 의지했던 두로와 시돈과의 동맹관계마저 끊어질 것이라는 선언은 그들의 완전한 고립을 보여줍니다. 갑돌 섬, 즉 그레데 섬에서 건너온 해양 민족이었던 블레셋은 그들의 군사력과 철기 문명을 자랑했지만, 하나님의 심판 앞에서는 아무것도 아니었습니다.\n\n예레미야는 "여호와의 칼이여 네가 언제까지 쉬지 않겠느냐"라는 탄식을 통해 심판의 엄중함을 전합니다. 그러나 이 칼은 하나님께서 명령하신 것이기에 멈출 수 없습니다. 이는 하나님의 공의가 반드시 실현된다는 진리를 보여줍니다. 블레셋을 향한 이 심판은 단순히 이스라엘의 원수를 갚는 차원이 아니라, 온 세상의 주권자이신 하나님께서 역사를 다스리신다는 분명한 선언입니다. 하나님을 대적하고 그의 백성을 괴롭히는 모든 세력은 결국 심판을 피할 수 없음을 블레셋의 운명을 통해 보여주고 있습니다.', E'오늘의 핵심\n하나님께서는 그의 백성을 대적하는 모든 세력을 심판하시며, 역사의 주권자로서 공의를 실현하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 뜻을 거스르며 의지하고 있는 ''블레셋''은 무엇입니까?\n2. 하나님의 심판이 피할 수 없는 것임을 알면서도 회개를 미루는 이유는 무엇일까요?\n3. 오늘 하나님의 주권 앞에 온전히 항복해야 할 영역은 어디입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-16', E'열방에 대한 심판 (예레미야 48장)', E'예레미야 48장', E'모압에 대한 심판의 선언이 전해집니다. 한때 이스라엘과 이웃하며 때로는 긴장 관계를, 때로는 교류를 이어왔던 모압이 이제 하나님의 심판을 피할 수 없게 되었습니다. 예레미야는 모압의 주요 성읍들이 차례로 무너질 것을 예언하면서, 그들이 섬기던 신 그모스조차 포로로 끌려갈 것이라고 선포합니다.\n\n모압이 심판받는 핵심적인 이유는 그들의 교만이었습니다. "모압은 젊은 시절부터 평안하고 포로도 되지 아니하였으므로"(렘 48:11)라는 말씀처럼, 오랜 평화와 번영 속에서 그들은 스스로를 높이며 하나님을 거슬렀습니다. 특별히 그들은 이스라엘을 조롱하고 멸시했는데, 이는 하나님의 백성을 대적한 것이었습니다. 하나님께서는 모압의 교만과 거만함을 아시고, 그들의 자랑이 허탄하며 아무것도 이루지 못할 것임을 말씀하십니다.\n\n그런데 놀라운 것은 모압을 향한 하나님의 애통함입니다. 하나님께서는 모압을 위하여 우시고, 그들을 위하여 부르짖으신다고 말씀하십니다. 심판을 선포하시면서도 그들의 멸망을 안타까워하시는 하나님의 마음이 드러납니다. 이는 하나님께서 단순히 심판의 하나님이 아니라, 모든 민족을 사랑하시며 그들의 회개를 기다리시는 분이심을 보여줍니다.\n\n모압의 운명은 우리에게 중요한 교훈을 전해줍니다. 평안과 번영이 오래 지속될 때 오히려 교만에 빠지기 쉽고, 하나님을 잊어버리기 쉽다는 것입니다. 모압처럼 우리도 현재의 안정과 성공이 영원할 것이라 착각할 수 있습니다. 그러나 모든 것은 하나님의 은혜로 주어진 것이며, 겸손히 그분을 의지할 때만이 참된 평안을 누릴 수 있습니다.', E'오늘의 핵심\n하나님께서는 교만한 모압을 심판하시면서도 그들을 위해 애통해하시며, 이를 통해 모든 민족을 다스리시는 공의로우시면서도 긍휼이 풍성하신 하나님의 성품을 보여주십니다.\n\n묵상 질문\n1. 오늘 내가 자랑하고 의지하는 것들이 혹시 하나님보다 앞서 있지는 않나요?\n2. 평안과 번영 속에서도 하나님을 잊지 않기 위해 어떤 영적 훈련이 필요할까요?\n3. 심판 중에도 애통해하시는 하나님의 마음을 느낄 때, 나는 어떻게 반응하게 되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-17', E'세계를 향한 심판 (예레미야 49장)', E'예레미야 49장', E'암몬을 비롯한 여러 민족들에 대한 심판 예언이 계속되고 있습니다. 암몬은 이스라엘의 영토인 갓 지파의 땅을 침략하여 점령하고 있었습니다. 하나님께서는 이러한 암몬의 불의한 행위에 대해 심판을 선언하시며, 그들의 수도 랍바가 폐허더미가 될 것이라고 말씀하십니다. 흥미로운 것은 심판 선언 가운데서도 "그 후에 내가 암몬 자손의 포로를 돌아가게 하리라"(렘 49:6)는 회복의 약속이 담겨 있다는 점입니다.\n\n에돔에 대한 심판 예언은 더욱 준엄합니다. 한때 지혜로 유명했던 데만이 그 지혜를 잃어버리고, 교만했던 에돔이 독수리처럼 높은 곳에 보금자리를 지었지만 하나님께서 그들을 끌어내리실 것입니다. 에돔의 교만과 자만은 그들을 속였고, 결국 소돔과 고모라처럼 황폐하게 될 것이라는 선언이 이어집니다.\n\n다메섹과 게달, 하솔, 엘람 등 다양한 민족들에 대한 심판도 선포됩니다. 찬송의 성읍이라 불리던 다메섹도 피곤하여 달아나려 하고, 평화롭게 살던 게달과 하솔도 느부갓네살의 침략을 받게 됩니다. 각 민족에 대한 심판 선언은 구체적이고 세밀하여, 하나님께서 모든 민족의 역사에 깊이 관여하고 계심을 보여줍니다.\n\n이 장에서 주목할 것은 하나님의 심판이 단순히 이스라엘의 원수들을 벌하는 것이 아니라는 점입니다. 각 민족의 죄악 - 불의한 침략, 교만, 우상숭배 - 에 대한 공의로운 심판이며, 동시에 일부 민족들에게는 회복의 가능성도 열어두고 계십니다. 이는 하나님께서 온 세상의 주권자이시며, 모든 민족을 동일한 공의의 기준으로 다스리신다는 것을 보여줍니다.', E'오늘의 핵심\n하나님께서는 이스라엘뿐 아니라 모든 민족들의 역사를 주관하시며, 각 민족의 불의와 교만을 동일한 공의의 기준으로 심판하십니다.\n\n묵상 질문\n1. 하나님께서 모든 민족을 세밀히 아시고 심판하신다는 사실이 나에게 어떤 의미로 다가옵니까?\n2. 에돔처럼 높은 곳에 자신을 세우려는 교만이 내 삶에는 없는지 돌아보셨습니까?\n3. 심판 중에도 회복을 약속하시는 하나님의 은혜에 어떻게 반응하고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-18', E'세계를 향한 심판 (예레미야 50장)', E'예레미야 50장', E'예레미야는 바벨론의 멸망과 이스라엘의 회복에 관한 하나님의 말씀을 선포합니다. 한때 하나님의 심판 도구로 사용되었던 바벨론이 이제는 심판의 대상이 되었습니다. 바벨론의 신들인 벨과 므로닥이 부서질 것이며, 북쪽에서 한 나라가 일어나 바벨론을 황폐케 할 것이라는 예언이 선포됩니다. 하늘을 찌를 듯한 기세로 고대 근동을 제패했던 대제국도 결국 하나님의 주권적 통치 아래 있음을 보여줍니다.\n\n바벨론의 심판 선언과 함께 이스라엘의 회복에 대한 소망의 메시지가 전해집니다. 포로로 끌려갔던 이스라엘과 유다 자손이 울면서 돌아와 여호와를 찾으며, 영원한 언약으로 하나님과 연합하게 될 것입니다. 예레미야는 이스라엘을 "잃어버린 양 떼"(렘 50:6)로 묘사하며, 목자들의 잘못된 인도로 방황했던 백성의 모습을 그려냅니다. 앗수르와 바벨론이라는 사자들에게 뜯기고 뼈가 꺾였던 이스라엘이 다시 본향으로 돌아와 갈멜과 바산에서 평화롭게 살게 될 것입니다.\n\n바벨론이 심판받는 이유는 분명합니다. 하나님께서 이스라엘을 징계하는 도구로 사용하셨지만, 바벨론은 그 권한을 넘어서서 잔인하게 행했고, 무엇보다 "이스라엘의 거룩한 자 여호와를 향하여 교만"했기 때문입니다. 온 세계의 망치로 불리던 바벨론이 꺾여 부서지고, 교만한 자가 넘어져도 일으킬 자가 없을 것이라는 선언은 역사의 주관자이신 하나님의 주권을 분명히 보여줍니다.\n\n특별히 주목할 것은 하나님께서 이스라엘의 구원자로서 자신을 계시하시는 부분입니다. "그들의 구원자는 강하니 그의 이름은 만군의 여호와"라는 선언은 포로 된 백성들에게 큰 위로가 되었을 것입니다. 하나님은 자기 백성을 위해 싸우시며, 그들의 죄악을 완전히 용서하여 "이스라엘의 죄악을 찾을지라도 없겠고 유다의 죄를 찾을지라도 찾아내지 못하리라"고 약속하십니다. 심판 가운데서도 은혜를 베푸시는 하나님의 신실하심이 빛나는 대목입니다.', E'오늘의 핵심\n세상의 강대국도 하나님의 주권적 통치 아래 있으며, 하나님은 자기 백성을 징계하시지만 결국 회복시키시는 신실한 구원자이십니다.\n\n묵상 질문\n1. 나는 세상의 권세와 힘 앞에서 하나님의 주권을 온전히 신뢰하고 있나요?\n2. "잃어버린 양"처럼 방황했던 내 삶을 하나님께서 어떻게 회복시켜 주셨나요?\n3. 하나님의 징계 속에서도 변함없는 그분의 사랑을 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-19', E'무너지는 예루살렘 (예레미야애가 1장)', E'예레미야애가 1장', E'예레미야애가는 예루살렘 성이 무너진 후 그 처참한 광경을 바라보며 아파한 예레미야의 슬픔 노래입니다. 왕과 많은 백성이 바벨론으로 끌려가고, 성안에서도 많은 사람이 죽임을 당했습니다. 한때 사람들로 북적이던 도성이 이제는 과부처럼 외로이 앉아 밤새 슬피 우는 모습으로 묘사됩니다. 사랑하던 이웃 나라들 중에 위로하는 자가 하나도 없고, 오히려 동맹국들마저 배반하여 원수가 되었습니다.\n\n이 비극적 상황의 원인을 예레미야는 분명히 밝힙니다. "예루살렘이 크게 범죄함으로 조소거리가 되었으니"(애 1:8)라는 고백처럼, 이 모든 고난은 하나님께 대한 반역의 결과였습니다. 제사장들과 장로들은 양식을 구하다가 성 가운데서 기절하고, 처녀들과 청년들은 사로잡혀 갔습니다. 한때 영광스러웠던 예루살렘의 지도자들은 이제 꼴을 찾지 못한 사슴처럼 힘없이 도망치는 신세가 되었습니다.\n\n예레미야의 애가에서 특별히 주목할 것은 하나님의 의로우심에 대한 인정입니다. "여호와는 의로우시도다 그러나 내가 그의 명령을 거역하였도다"라는 고백은 이 모든 심판이 정당함을 인정하는 신앙의 고백입니다. 동시에 예레미야는 하나님께 간절히 호소합니다. 자신들의 고통을 돌아보시고, 원수들이 기뻐하는 이 상황에서 긍휼을 베풀어 주시기를 간구합니다.\n\n하나님과의 만남의 상징이자 생명의 상징이었던 예루살렘의 멸망을 보며 예레미야가 흘리는 눈물은 곧 하나님의 눈물과도 같았습니다. 항복하라는 예레미야의 예언을 멸시하던 지도자들은 어디에도 보이지 않고, 모욕과 비방을 들으면서도 끝까지 하나님의 말씀을 외치던 선지자만이 잿더미가 된 성읍을 배회하며 울부짖고 있습니다. 그의 눈물은 단순한 감상이 아니라 하나님의 마음을 품은 중보자의 눈물이었습니다.', E'오늘의 핵심\n예루살렘의 멸망은 하나님께 대한 반역의 결과였지만, 예레미야는 하나님의 의로우심을 인정하면서도 긍휼을 구하는 신앙의 균형을 보여줍니다.\n\n묵상 질문\n1. 내 삶의 어려움 속에서도 하나님의 의로우심을 인정할 수 있나요?\n2. 죄의 결과로 인한 고통 속에서도 하나님께 긍휼을 구하고 있나요?\n3. 공동체의 아픔을 나의 아픔으로 품고 중보하는 마음이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-21', E'무너지는 예루살렘 (예레미야애가 2장)', E'예레미야애가 2장', E'예레미야애가 2장은 예루살렘 성의 파괴를 목도한 예레미야가 하나님의 진노를 생생하게 묘사하는 애가입니다. "슬프다"로 시작되는 이 탄식의 노래는 한때 아름답고 영광스러웠던 시온이 하나님의 심판으로 완전히 무너진 모습을 그려냅니다. 하나님께서는 진노하셔서 성전과 성벽을 무너뜨리시고, 왕과 제사장을 버리시며, 절기와 안식일마저 잊어버리게 하셨습니다.\n\n예레미야의 눈에 비친 예루살렘의 모습은 참혹하기 그지없습니다. 한때 "온전한 영광"이요 "모든 세상 사람들의 기쁨"이라 불리던 도성이 이제는 원수들의 조롱거리가 되었습니다. 성읍 길거리에는 굶주림으로 기절하는 어린아이들과 젖먹이들이 널려 있고, 그들은 어머니 품에서 숨을 거두며 "곡식과 포도주가 어디 있느냐"고 묻습니다. 이 처참한 광경 앞에서 선지자는 자신의 창자가 끊어지고 간이 땅에 쏟아지는 듯한 고통을 느낍니다.\n\n특별히 주목할 점은 이 모든 재앙이 바벨론의 공격 때문이 아니라 하나님께서 직접 행하신 일이라는 사실입니다. 하나님께서 "원수같이" 되어 이스라엘을 삼키시고, 마치 활을 당기듯 심판의 화살을 쏘셨다는 표현은 언약 백성을 향한 하나님의 진노가 얼마나 크셨는지를 보여줍니다. 거짓 평안을 전하던 선지자들의 헛된 예언과 백성들의 완고한 불순종이 결국 이런 비극을 초래했던 것입니다.\n\n그러나 예레미야는 절망 가운데서도 기도를 멈추지 않습니다. "네 마음을 주의 얼굴 앞에 물 쏟듯 할지어다"라는 권면은 가장 어두운 심판의 때에도 하나님께 나아가는 것만이 유일한 소망임을 일깨워 줍니다. 비록 지금은 하나님의 진노로 모든 것이 무너졌지만, 그 하나님께 부르짖는 것 외에는 다른 길이 없음을 예레미야는 알고 있었습니다.', E'오늘의 핵심\n하나님께서는 언약을 배반한 백성들에게 철저한 심판을 행하셨지만, 예레미야는 그 절망적인 상황에서도 하나님께 부르짖으며 회복의 소망을 포기하지 않았습니다.\n\n묵상 질문\n1. 하나님의 심판이 이토록 철저했던 이유는 무엇이며, 오늘 나에게 주시는 경고는 무엇일까요?\n2. 가장 어려운 상황에서도 하나님께 나아가는 것이 유일한 길임을 믿고 있나요?\n3. 내 삶에서 하나님보다 더 의지하고 있는 거짓 평안은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-22', E'주의 인자와 긍휼 (예레미야애가 3장)', E'예레미야애가 3장', E'예레미야는 심연에서 부르짖습니다. "여호와의 분노의 매로 말미암아 고난 당한 자는 나로다"(애 3:1). 예루살렘 멸망의 참상을 목격한 선지자의 탄식은 생생한 고통의 언어로 가득합니다. 어둠, 사슬, 눈물, 조롱이 그를 둘러쌉니다. 하나님께서 활을 당겨 자신을 과녁으로 삼으셨다는 표현은 그가 느끼는 절망의 깊이를 보여줍니다. 급기야 18절에서 그는 "나의 힘과 여호와께 대한 내 소망이 끊어졌다"고 고백합니다. 하나님의 선지자가 하나님께 대한 소망이 끊어졌다고 말하는 이 역설적 상황이 바로 인간이 경험할 수 있는 가장 깊은 영적 어둠입니다.\n\n그런데 21절부터 놀라운 전환이 일어납니다. "이것을 내가 내 마음에 담아 두었더니 그것이 오히려 나의 소망이 되었사옴은." 무엇이 그의 소망이 되었을까요? 바로 우리가 ''진멸되지 아니함''입니다. 예루살렘은 폐허가 되었지만, 백성이 완전히 사라지지는 않았습니다. 포로로 끌려갔지만 남은 자가 있었습니다. 예레미야는 이 작은 틈새에서 하나님의 인자와 긍휼을 발견합니다. "여호와의 인자와 긍휼이 무궁하시므로 우리가 진멸되지 아니함이니이다. 이것들이 아침마다 새로우니 주의 성실하심이 크시도소이다"(22-23절).\n\n특별히 33절의 고백이 우리 가슴을 울립니다. "주께서 인생으로 고생하게 하시며 근심하게 하심은 본심이 아니시로다." 하나님의 본심은 고통을 주시는 것이 아니라는 것입니다. 징계 가운데서도 긍휼을 베푸시고, 심판 속에서도 회복의 씨앗을 남기시는 분이 우리 하나님이십니다. 예레미야는 이 진리를 붙잡고 40절에서 권면합니다. "우리가 스스로 우리의 행위들을 조사하고 여호와께로 돌아가자."\n\n오늘 우리도 깊은 고통 속에 있을 수 있습니다. 기도해도 응답이 없고, 하늘이 닫힌 것처럼 느껴질 때가 있습니다. 그러나 예레미야가 발견한 것처럼, 완전히 끝난 것 같은 상황에서도 하나님은 작은 소망의 빛을 남겨두십니다. 그 빛은 아침마다 새로운 하나님의 인자하심입니다. 어제의 실패가 오늘의 은혜를 막을 수 없습니다. 지금 내게 남아 있는 것이 무엇인지 돌아보십시오. 그 작은 것 속에 담긴 하나님의 긍휼을 발견하시길 바랍니다.', E'오늘의 핵심\n예레미야는 절망의 바닥에서도 ''진멸되지 아니함''이라는 작은 틈새를 통해 하나님의 무궁한 인자와 긍휼을 발견하고, 아침마다 새로운 주의 성실하심을 고백합니다.\n\n묵상 질문\n1. 내 인생의 가장 깊은 절망 속에서 하나님은 어떤 작은 소망을 남겨두셨나요?\n2. ''아침마다 새로운'' 하나님의 인자하심을 오늘 어떻게 경험할 수 있을까요?\n3. 고통이 하나님의 본심이 아니라면, 내 고난을 통해 하나님이 이루실 선한 뜻은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-23', E'주의 인자와 긍휼 (예레미야애가 4장)', E'예레미야애가 4장', E'예레미야애가 4장은 예루살렘 멸망의 처참한 현실을 가장 생생하게 보여줍니다. "슬프다 어찌 그리 금이 빛을 잃고 순금이 변질하였으며"라는 탄식으로 시작되는 이 장은 한때 영광스러웠던 도시의 비참한 몰락을 그립니다. 성전의 금과 보석들이 거리에 흩어진 것처럼, 하나님의 백성들도 그 존귀함을 잃고 질그릇처럼 버려졌습니다.\n\n특히 가슴 아픈 것은 아이들의 고통입니다. 젖먹이들이 목말라 혀가 입천장에 붙고, 어린아이들이 떡을 구해도 줄 사람이 없다는 묘사는 도시가 얼마나 철저히 파괴되었는지를 보여줍니다. 더 충격적인 것은 10절의 기록입니다. 극심한 기근으로 자비로운 어머니들조차 자기 자녀를 삶아 먹었다는 것입니다. 이는 신명기 28장에 예언된 언약의 저주가 그대로 성취된 것이었습니다.\n\n그런데 예레미야는 이 비극의 근본 원인을 13절에서 분명히 밝힙니다. "그의 선지자들의 죄들과 제사장들의 죄악들 때문이니." 영적 지도자들이 먼저 타락했고, 의인들의 피를 흘렸습니다. 하나님의 말씀을 전해야 할 선지자들이 거짓을 말했고, 거룩함을 지켜야 할 제사장들이 불의를 행했습니다. 지도자들의 실패가 온 공동체를 멸망으로 이끌었던 것입니다.\n\n17절은 또 다른 교훈을 줍니다. "우리를 구원하지 못할 나라를 바라보고 바라보았도다." 유다는 애굽의 도움을 기대했지만 헛된 소망이었습니다. 하나님을 떠나 세상 권력을 의지한 결과는 철저한 배신과 실망뿐이었습니다. 그들이 의지했던 왕조차 20절에서 보듯이 적의 함정에 빠지고 말았습니다.\n\n그러나 예레미야는 22절에서 희망의 빛을 비춥니다. "딸 시온아 네 죄악의 형벌이 다하였으니." 심판은 영원하지 않습니다. 하나님의 징계에는 끝이 있으며, 회복의 날이 올 것입니다. 비록 지금은 폐허가 되었지만, 하나님께서는 당신의 백성을 완전히 버리지 않으셨습니다. 오히려 이 철저한 심판을 통해 새로운 시작을 준비하고 계셨던 것입니다.', E'오늘의 핵심\n영적 지도자들의 타락이 공동체 전체를 멸망으로 이끌었지만, 하나님께서는 심판 가운데서도 형벌의 끝과 회복의 소망을 약속하십니다.\n\n묵상 질문\n1. 영적 지도자의 책임이 왜 그토록 무거운 것일까요?\n2. 내가 하나님보다 더 의지하고 있는 ''애굽''은 무엇인가요?\n3. 징계 가운데서도 끝이 있다는 하나님의 약속이 내게 어떤 위로가 되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-24', E'주의 인자와 긍휼 (예레미야애가 5장)', E'예레미야애가 5장', E'예레미야애가의 마지막 장은 기도로 시작합니다. "여호와여 우리가 당한 것을 기억하시고 우리가 받은 치욕을 살펴보옵소서"(1절). 이 간절한 호소에는 예루살렘 멸망 이후 백성들이 겪어야 했던 처참한 현실이 담겨 있습니다. 기업이 외인들에게 넘어가고, 집들은 이방인들이 차지했습니다. 더 아픈 것은 그들 스스로를 "아버지 없는 고아들"이요 "과부들"로 표현하는 대목입니다. 하나님과의 관계가 단절된 것 같은 영적 고아 상태를 토로하는 것입니다.\n\n생존을 위한 몸부림도 처절합니다. 물 한 모금도 돈을 주고 사 마셔야 하고, 나무 하나도 값을 치러야 얻을 수 있습니다. 애굽과 앗수르에 손을 내밀어 구걸하듯 양식을 구하는 모습은, 한때 젖과 꿀이 흐르는 약속의 땅에 살던 그들에게는 치욕스러운 일이었을 것입니다. 예레미야는 이 모든 고통의 원인을 정확히 직시합니다. "우리의 머리에서는 면류관이 떨어졌사오니 오호라 우리의 범죄 때문이니이다"(16절). 조상들의 죄와 자신들의 죄가 이 모든 비극을 불러왔음을 인정하는 것입니다.\n\n그러나 이 애가의 절정은 19절에서 시작됩니다. "여호와여 주는 영원히 계시오며 주의 보좌는 대대에 이르나이다." 폐허가 된 예루살렘, 무너진 성전을 보면서도 예레미야는 변하지 않는 한 가지를 붙잡습니다. 하나님의 영원하심과 그분의 주권입니다. 그리고 가장 아름다운 기도가 이어집니다. "여호와여 우리를 주께로 돌이키소서 그리하시면 우리가 주께로 돌아가겠사오니"(21절). \n\n이 기도에는 깊은 신학이 담겨 있습니다. 인간의 회개조차 하나님의 은혜가 먼저 있어야 가능하다는 고백입니다. 하나님께서 먼저 우리를 돌이키실 때, 비로소 우리도 돌아갈 수 있습니다. 이것이 바로 하나님의 선행은총입니다. 예레미야애가는 22절의 불확실한 탄식으로 끝나지만, 이미 21절의 기도 속에 소망의 씨앗이 심어져 있습니다. 하나님의 신실하심을 믿는 자의 기도는 결코 헛되지 않을 것입니다.', E'오늘의 핵심\n예레미야는 처참한 현실 속에서도 영원하신 하나님의 주권을 붙잡고, 회개조차 하나님의 은혜로만 가능함을 고백하며 회복을 간구합니다.\n\n묵상 질문\n1. 고통의 원인을 인정하면서도 하나님께 나아갈 수 있는 이유는 무엇일까요?\n2. "우리를 주께로 돌이키소서"라는 기도가 내 삶에 필요한 영역은 어디인가요?\n3. 변하는 상황 속에서도 변하지 않는 하나님의 속성을 어떻게 붙잡을 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-25', E'심판받는 이스라엘 (에스겔 1장)', E'에스겔 1장', E'포로로 끌려간 지 5년, 그발 강가에서 제사장 에스겔에게 하나님의 영광이 나타났습니다. 북방에서 몰려오는 폭풍과 구름, 번쩍이는 불과 빛은 압도적인 하나님의 임재를 보여주었습니다. 그 가운데 나타난 네 생물의 형상은 각각 사람, 사자, 소, 독수리의 얼굴을 가졌으며, 그들의 날개 아래에는 사람의 손이 있었습니다. 이들은 하나님의 영이 이끄시는 대로 돌이키지 않고 곧게 나아갔으며, 그들 곁의 바퀴들도 함께 움직였습니다. 바퀴 안의 바퀴, 눈으로 가득한 둘레는 하나님의 전지하심과 무소부재하심을 나타냅니다.\n\n생물들의 머리 위에는 수정 같은 궁창이 펼쳐져 있었고, 그 위에는 남보석 같은 보좌가 있었습니다. 보좌 위에는 사람의 모양을 한 형상이 계셨는데, 허리 위아래로 불과 같은 광채가 났습니다. 에스겔이 본 것은 "여호와의 영광의 형상"(겔 1:28)이었습니다. 이는 예루살렘 성전을 떠나신 하나님께서 포로들이 있는 바벨론 땅에서도 여전히 그들과 함께 계심을 보여주는 놀라운 계시였습니다.\n\n이스라엘이 죄로 인해 심판받고 성전이 파괴될 운명에 있었지만, 하나님의 영광은 지역과 장소에 제한받지 않으셨습니다. 오히려 절망의 땅 바벨론에서도 하나님은 당신의 백성과 함께하시며, 새로운 소망의 메시지를 전할 예언자를 부르고 계셨습니다. 에스겔이 엎드려 들은 그 음성은 곧 이스라엘의 회복과 구원을 향한 하나님의 계획이 시작되고 있음을 알리는 신호였습니다.', E'오늘의 핵심\n포로의 땅 바벨론에서도 하나님의 영광은 여전히 임재하시며, 절망 가운데서도 당신의 백성과 함께하시는 하나님의 신실하심이 나타납니다.\n\n묵상 질문\n1. 내 삶의 ''바벨론'', 즉 절망적인 상황에서도 하나님이 함께하심을 경험한 적이 있나요?\n2. 에스겔처럼 하나님의 영광 앞에 엎드려 그분의 음성을 듣고자 하는 마음이 있으신가요?\n3. 하나님의 임재가 장소에 제한받지 않으신다는 사실이 오늘 나에게 어떤 위로와 소망을 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-26', E'심판받는 이스라엘 (에스겔 2장)', E'에스겔 2장', E'하나님의 영광을 목격한 에스겔은 얼굴을 땅에 대고 엎드려 있었습니다. 그때 하나님께서는 "인자야 네 발로 일어서라 내가 네게 말하리라"고 명하십니다. 놀랍게도 하나님이 말씀하실 때 그 영이 에스겔에게 임하여 그를 일으켜 세우셨습니다. 이는 하나님의 부르심이 단순히 인간의 의지나 능력에 달린 것이 아니라, 하나님의 영이 함께하실 때 비로소 가능함을 보여줍니다.\n\n하나님께서는 에스겔을 "패역한 백성, 나를 배반하는 자"인 이스라엘 자손에게 보내신다고 말씀하십니다. 그들은 조상 때부터 하나님을 거역해 왔고, 얼굴이 뻔뻔하며 마음이 굳은 상태였습니다. 그런데도 하나님은 포기하지 않으시고 선지자를 보내십니다. 비록 그들이 듣든지 듣지 않든지, 그들 가운데 선지자가 있음을 알게 하시려는 것입니다. 이는 끝까지 기회를 주시는 하나님의 사랑과, 동시에 더 이상 변명할 수 없게 하시는 공의로움을 드러냅니다.\n\n특별히 주목할 것은 하나님께서 에스겔에게 주신 격려의 말씀입니다. "비록 가시와 찔레와 함께 있으며 전갈 가운데에 거주할지라도" 두려워하지 말라고 하십니다. 선지자의 사역이 얼마나 위험하고 고통스러울지를 미리 아시면서도, 하나님은 에스겔이 담대히 말씀을 전하기를 원하셨습니다. \n\n장면은 극적으로 전환되어, 하나님의 손에서 두루마리가 펼쳐집니다. 그 안팎에는 애가와 애곡과 재앙의 말이 가득했습니다. 에스겔은 이 슬픈 메시지를 먹어야 했고, 그것을 백성에게 전해야 했습니다. 심판의 메시지를 전하는 것은 선지자에게도 고통스러운 일이었지만, 이것이 하나님께서 주신 사명이었습니다.', E'오늘의 핵심\n하나님께서는 패역한 백성에게 끝까지 선지자를 보내시어 돌이킬 기회를 주시지만, 동시에 그들이 더 이상 변명할 수 없도록 분명한 심판의 메시지를 전하게 하십니다.\n\n묵상 질문\n1. 하나님의 부르심 앞에 선 에스겔처럼, 나도 하나님의 영으로 일으켜 세움을 받은 경험이 있나요?\n2. 어려운 상황 속에서도 하나님의 말씀을 전해야 할 때, 어떤 두려움이 나를 주저하게 만드나요?\n3. 내가 전해야 할 말씀이 듣기 좋은 것만이 아닐 때, 그것을 어떻게 사랑으로 전할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-28', E'심판받는 이스라엘 (에스겔 3장)', E'에스겔 3장', E'에스겔이 부름받은 선지자의 사명은 결코 쉬운 길이 아니었습니다. 하나님께서는 두루마리를 먹이시며 그 말씀을 온전히 소화하여 전하라고 명하십니다. 놀랍게도 그 두루마리는 "달기가 꿀 같더라"(겔 3:3)고 고백합니다. 심판의 메시지조차도 하나님의 말씀이기에 달콤함을 경험한 것입니다. 이는 예언자가 하나님의 마음과 하나 되어 그 뜻을 온전히 받아들였음을 보여줍니다.\n\n하나님께서는 에스겔을 언어가 통하지 않는 이방 민족이 아닌 이스라엘 백성에게 보내십니다. 그러나 오히려 이방인들이 하나님의 말씀을 더 잘 들었을 것이라는 역설적인 말씀을 하십니다. 동족인 이스라엘 백성은 "이마가 굳고 마음이 굳어" 하나님의 말씀을 거부할 것이라는 예고입니다. 이에 하나님께서는 에스겔의 이마를 금강석같이 단단하게 하시어 반역하는 백성들 앞에서도 굴하지 않고 사명을 감당할 수 있도록 준비시키십니다.\n\n특별히 하나님께서는 에스겔을 "파수꾼"으로 세우십니다. 파수꾼은 위험을 미리 알려 백성을 보호하는 중대한 책임을 지닌 자입니다. 악인에게 경고하지 않으면 그 피값을 파수꾼에게서 찾겠다는 엄중한 말씀은 영혼을 향한 하나님의 간절한 마음을 보여줍니다. 의인이 타락할 때도 마찬가지로 경고해야 할 책임이 있습니다. 이는 구원받은 자도 계속해서 하나님의 말씀으로 깨어있어야 함을 가르칩니다.\n\n그발 강가에서 하나님의 영광을 다시 목격한 에스겔은 엎드릴 수밖에 없었습니다. 그러나 주의 영이 그를 일으켜 세우십니다. 이는 하나님의 능력으로만 그 사명을 감당할 수 있음을 보여주는 장면입니다. 비록 백성들이 그를 결박하고 그의 혀가 입천장에 붙어 잠시 침묵하게 될지라도, 하나님께서 말씀하실 때 그 입은 열릴 것입니다. 패역한 백성 가운데서도 하나님의 때에 하나님의 방법으로 말씀은 선포될 것입니다.', E'오늘의 핵심\n하나님께서는 에스겔을 이스라엘의 파수꾼으로 세우시며, 듣기를 거부하는 완악한 백성에게도 끝까지 경고의 메시지를 전하도록 하십니다.\n\n묵상 질문\n1. 하나님의 말씀이 내게는 꿀처럼 달콤하게 느껴지나요, 아니면 부담스럽게 느껴지나요?\n2. 내가 누군가의 영적 파수꾼 역할을 해야 할 사람은 누구인가요?\n3. 말씀을 전하기 어려운 상황에서도 하나님의 능력을 의지한 경험이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-29', E'심판받는 이스라엘 (에스겔 4장)', E'에스겔 4장', E'하나님께서는 에스겔에게 독특한 상징적 행동을 명령하십니다. 토판에 예루살렘 성을 그리고, 그 주위에 포위 공격의 모습을 재현하라고 하십니다. 사다리와 흙언덕, 진영과 공성퇴를 설치하고, 철판으로 철벽을 만들어 놓으라는 것입니다. 이 생생한 모형은 곧 닥쳐올 예루살렘의 운명을 미리 보여주는 징조였습니다.\n\n더욱 놀라운 것은 에스겔이 직접 몸으로 표현해야 할 내용입니다. 왼쪽으로 390일간 누워 북이스라엘의 죄를, 오른쪽으로 40일간 누워 남유다의 죄를 담당하라고 하십니다. 하루가 일 년을 상징하는 이 기간은 각각 이스라엘과 유다가 하나님을 떠나 있던 세월을 나타냅니다. 하나님께서는 줄로 에스겔을 묶어 그가 몸을 돌릴 수도 없게 하심으로써, 심판의 확정성과 불가피성을 보여주십니다.\n\n포위된 성에서 겪을 기근의 참상도 미리 체험하게 하십니다. 하루에 약 230그램의 혼합 곡물 떡과 0.6리터의 물만으로 연명하는 것은 극심한 식량 부족 상황을 나타냅니다. 특히 인분으로 불을 피워 떡을 굽는 것은 이방 땅에서 겪을 부정함과 수치를 상징합니다. 에스겔이 이를 거부하자 하나님께서 쇠똥으로 대체하도록 허락하신 것은, 선지자의 정결함을 배려하시면서도 메시지의 본질은 타협하지 않으시는 하나님의 성품을 보여줍니다.\n\n"내가 예루살렘에서 의뢰하는 양식을 끊으리니"(겔 4:16)라는 하나님의 선언은 단순한 물리적 기근이 아닙니다. 하나님을 떠나 우상과 권력을 의지했던 예루살렘이 마침내 그 모든 의지처를 잃고 절망 가운데 빠질 것을 예고합니다. 에스겔의 상징적 행동은 이 모든 심판의 메시지를 백성들의 눈앞에 생생하게 펼쳐 보이는 하나님의 마지막 경고였습니다.', E'오늘의 핵심\n하나님께서는 에스겔의 몸을 통한 상징적 행동으로 예루살렘에 임할 포위와 기근, 그리고 포로 생활의 비참함을 미리 보여주시며 회개를 촉구하십니다.\n\n묵상 질문\n1. 하나님께서 이토록 구체적이고 충격적인 방법으로 경고하시는 이유는 무엇일까요?\n2. 내 삶에서 하나님보다 더 의지하고 있는 ''양식''은 무엇인가요?\n3. 오늘 하나님께서 내게 보여주시는 경고의 징조를 무시하고 있지는 않나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-01', E'심판받는 이스라엘 (에스겔 5장)', E'에스겔 5장', E'에스겔은 하나님의 명령에 따라 매우 충격적인 상징 행동을 수행하게 됩니다. 날카로운 칼로 자신의 머리털과 수염을 깎아 저울로 달아 삼등분하는 모습은, 예루살렘에 임할 심판의 구체적인 모습을 보여주고 있습니다. 고대 근동에서 머리털과 수염은 한 사람의 정체성과 명예를 상징했기에, 이를 깎는다는 것은 철저한 수치와 파괴를 의미했습니다.\n\n삼분의 일은 성읍 안에서 불사르고, 삼분의 일은 칼로 치고, 나머지 삼분의 일은 바람에 흩어버리는 에스겔의 행동은 예루살렘 백성들이 당할 운명을 생생하게 보여줍니다. 전염병과 기근으로 죽는 자, 칼에 죽는 자, 그리고 사방으로 흩어질 자들의 모습이 예언자의 상징적 행동을 통해 미리 계시되고 있는 것입니다. 옷자락에 싸두었던 소량의 머리털마저 다시 불에 태우는 모습은 남은 자들조차 온전하지 못할 것임을 암시합니다.\n\n하나님께서는 예루살렘을 "이방인 가운데에 두어 나라들이 둘러 있게 하였거늘"(겔 5:5)이라고 말씀하십니다. 이는 예루살렘이 열방의 중심에서 하나님의 영광을 드러내는 특권적 위치에 있었음을 보여줍니다. 그러나 그들은 오히려 주변 이방 민족들보다 더 악을 행하며 하나님의 규례를 버렸습니다. 특별한 은혜를 받은 만큼 그들의 책임도 컸지만, 그들은 그 책임을 저버렸습니다.\n\n가장 충격적인 것은 "아버지가 아들을 잡아먹고 아들이 그 아버지를 잡아먹으리라"는 예언입니다. 이는 극도의 기근 상황에서 일어날 끔찍한 일을 암시하는데, 실제로 예루살렘 포위 때 이런 참상이 일어났다고 역사는 기록하고 있습니다. 하나님의 성소를 우상으로 더럽힌 결과가 얼마나 처참한지를 보여주는 대목입니다.\n\n이 모든 심판의 목적은 단순한 보복이 아니었습니다. "나 여호와가 열심으로 말한 줄을 그들이 알리라"는 말씀처럼, 하나님께서는 당신이 살아계신 참 하나님이심을 깨닫게 하려는 것이었습니다. 심판을 통해서라도 하나님의 거룩하심과 공의로우심을 드러내시는 하나님의 뜻이 담겨 있습니다.', E'오늘의 핵심\n하나님께서는 에스겔의 충격적인 상징 행동을 통해 예루살렘에 임할 심판의 구체적인 모습을 보여주시며, 특권을 받은 백성이 더 큰 책임을 져야 함을 일깨워 주십니다.\n\n묵상 질문\n1. 하나님께서 주신 특별한 은혜와 위치를 나는 어떻게 사용하고 있나요?\n2. 내 삶에서 하나님보다 더 중요하게 여기는 우상은 무엇인가요?\n3. 하나님의 경고를 듣고도 무시했던 경험이 있다면 어떤 것이었나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-02', E'심판받는 이스라엘 (에스겔 6장)', E'에스겔 6장', E'여호와의 말씀이 에스겔에게 임하여 이스라엘 산들을 향한 심판의 메시지를 전하게 하십니다. 하나님께서는 산과 언덕, 시내와 골짜기에 이르기까지 이스라엘 전 땅에 칼이 임할 것을 선포하십니다. 이 심판의 핵심은 우상숭배의 중심지인 산당들을 완전히 멸하시겠다는 것입니다. 제단들은 황폐하게 되고, 분향제단들은 깨어지며, 우상을 섬기던 자들의 시체가 바로 그 우상들 앞에 엎드러지게 될 것이라고 하나님은 말씀하십니다.\n\n이스라엘이 받게 될 심판의 모습은 참혹합니다. 먼 곳에 있는 자는 전염병으로, 가까운 곳에 있는 자는 칼에 죽임을 당하고, 살아남아 포위된 자들은 기근으로 죽게 될 것입니다. 그들이 우상에게 분향하던 모든 장소 - 높은 고개, 산꼭대기, 푸른 나무와 상수리나무 아래 - 에 시체가 널려있게 될 것입니다. 하나님께서는 이러한 철저한 심판을 통해 "내가 여호와인 줄을 너희가 알게 하려 함이라"고 그 목적을 분명히 밝히십니다.\n\n그러나 하나님의 심판 가운데서도 은혜의 빛줄기가 보입니다. 하나님께서는 "칼을 피하여 이방인들 중에 살아 남은 자가 있게 할지라"고 말씀하십니다. 포로로 끌려간 이들이 이방 땅에서 비로소 자신들의 죄를 깨닫고 회개하게 될 것입니다. 그들은 음란한 마음으로 하나님을 떠나 우상을 섬겼던 일을 기억하고 스스로 한탄하게 됩니다. 심판의 목적이 단순한 멸망이 아니라, 하나님을 알고 돌아오게 하는 것임을 보여줍니다. 광야에서부터 디블라까지 온 땅이 황폐하게 되는 심판을 통해서라도, 하나님께서는 당신의 백성이 여호와 하나님을 알기를 원하십니다.', E'오늘의 핵심\n하나님께서는 이스라엘의 우상숭배에 대한 철저한 심판을 선포하시면서도, 남은 자들이 회개하고 돌아올 수 있는 은혜의 길을 열어두십니다.\n\n묵상 질문\n1. 나의 삶에서 하나님보다 더 의지하고 있는 ''현대의 우상''은 무엇인가요?\n2. 하나님의 징계를 통해 깨달았던 경험이 있다면 무엇이었나요?\n3. 심판 중에도 은혜를 베푸시는 하나님의 마음을 어떻게 이해하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-03', E'심판받는 이스라엘 (에스겔 7장)', E'에스겔 7장', E'여호와의 말씀이 에스겔에게 임하여 이스라엘 땅에 대한 최후의 심판을 선포합니다. "끝났도다 이 땅 사방의 일이 끝났도다"라는 하나님의 선언은 더 이상의 유예나 기회가 없음을 분명히 보여줍니다. 반복적으로 울려 퍼지는 ''끝''이라는 단어는 심판의 확정성과 급박성을 강조하며, 이스라엘이 맞이할 운명의 무게를 전달합니다.\n\n하나님께서는 이스라엘의 죄악에 대해 더 이상 불쌍히 여기지도, 긍휼히 여기지도 않으시겠다고 선언하십니다. 그들이 화려한 장식으로 교만을 품고 금과 은으로 우상을 만들어 섬긴 죄악이 이제 그들에게 보응으로 돌아옵니다. 특히 주목할 것은 그들이 의지하던 재물이 심판의 날에는 아무런 도움이 되지 못한다는 사실입니다. 오히려 그 금과 은이 "죄악의 걸림돌"이 되어 거리에 던져질 오물처럼 취급받게 됩니다.\n\n심판의 도구로 사용되는 것은 극악한 이방인들입니다. 하나님께서는 바벨론을 통해 이스라엘을 치시며, 성소마저 더럽혀지도록 허락하십니다. 전쟁의 나팔이 울려도 싸울 사람이 없고, 선지자에게 묵시를 구해도 헛되며, 제사장에게는 율법이, 장로에게는 지혜가 사라집니다. 이는 하나님과의 관계가 단절될 때 나타나는 영적 공백과 혼란의 극치를 보여줍니다.\n\n그러나 이 엄중한 심판의 메시지 속에서도 하나님의 궁극적인 목적은 분명합니다. "내가 여호와인 줄을 너희가 알리라"는 말씀이 반복되는 것은, 심판을 통해서라도 하나님께서 자신이 누구신지를 알게 하시려는 하나님의 뜻을 드러냅니다. 죄악으로 어두워진 백성의 영적 눈을 여시고자 하는 하나님의 아픈 사랑이 엄중한 심판의 메시지 뒤에 숨어 있습니다.', E'오늘의 핵심\n하나님께서는 이스라엘의 끝없는 죄악에 대해 최후의 심판을 선포하시며, 그들이 의지하던 모든 것이 무너질 때 비로소 여호와 하나님이 누구신지 알게 될 것임을 말씀하십니다.\n\n묵상 질문\n1. 내가 하나님보다 더 의지하고 있는 ''금과 은''은 무엇인가요?\n2. 반복되는 하나님의 경고를 무시하고 있는 나의 모습은 없나요?\n3. 하나님께서 "내가 여호와인 줄 알리라"고 하신 말씀이 오늘 내게 어떤 의미로 다가오나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-04', E'예루살렘의 죄악과 심판 (에스겔 8장)', E'에스겔 8장', E'포로로 잡혀간 지 여섯째 해 여섯째 달 초닷새, 에스겔이 자신의 집에서 유다 장로들과 함께 앉아 있을 때 하나님의 권능이 그에게 임했습니다. 하나님께서는 환상 중에 에스겔을 예루살렘 성전으로 데려가셔서 그곳에서 벌어지고 있는 충격적인 광경을 보여주셨습니다. 이 환상은 예루살렘 성전의 영적 타락이 얼마나 심각한 지경에 이르렀는지를 생생하게 드러내 주고 있습니다.\n\n성전 북문 입구에는 ''질투의 우상''이 세워져 있었습니다. 이것은 하나님의 질투를 불러일으키는 우상으로, 성전 안에 이방신의 형상이 버젓이 자리 잡고 있었던 것입니다. 더 깊이 들어가자 칠십 명의 장로들이 은밀한 방에서 벽에 그려진 각종 우상들에게 분향하며 예배하고 있었습니다. 그들은 "여호와께서 우리를 보지 아니하시며 여호와께서 이 땅을 버리셨다"(겔 8:12)고 말하며 자신들의 우상숭배를 정당화했습니다. 하나님께서 보지 않으신다는 그들의 착각이 얼마나 어리석은 것인지, 바로 그 순간 하나님께서는 에스겔을 통해 그들의 은밀한 죄악을 낱낱이 보고 계셨습니다.\n\n성전 북문에서는 여인들이 바벨론의 풍요신 담무스를 위해 애곡하고 있었고, 성전 안뜰에서는 스물다섯 명의 제사장들이 하나님의 성전을 등지고 동쪽 태양을 향해 절하고 있었습니다. 하나님을 섬겨야 할 성전이 온갖 우상숭배의 온상이 되어 있었던 것입니다. 이러한 영적 타락은 단순히 종교적 의식의 문제가 아니라 하나님과의 언약 관계를 완전히 파기하는 배신 행위였습니다. 하나님께서는 이 모든 가증한 일들을 보시고 진노하셨으며, 더 이상 긍휼을 베풀지 않으시겠다고 선언하셨습니다. 성전은 하나님의 임재의 처소였지만, 백성들의 우상숭배로 인해 하나님께서는 그곳을 떠나실 수밖에 없으셨습니다.', E'오늘의 핵심\n하나님께서는 에스겔에게 예루살렘 성전에서 은밀히 행해지는 우상숭배의 실상을 보여주심으로써, 심판이 불가피함을 깨닫게 하셨습니다. 하나님의 성전이 우상의 전으로 변질된 것은 영적 타락의 극치를 보여줍니다.\n\n묵상 질문\n1. 내 삶에서 하나님보다 더 중요하게 여기는 ''질투의 우상''은 무엇인가요?\n2. "하나님이 보지 않으신다"는 착각 속에서 은밀히 행하는 일이 있다면 무엇일까요?\n3. 하나님의 임재가 떠나가실 만큼 심각한 영적 문제가 내 안에 있지는 않은가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-06', E'예루살렘의 죄악과 심판 (에스겔 9장)', E'에스겔 9장', E'하나님의 영광이 성전을 떠나기 직전, 예루살렘에 대한 최후의 심판이 시작됩니다. 에스겔이 본 환상 속에서 하나님은 여섯 명의 심판 집행자를 부르시는데, 그들은 각자 손에 죽이는 무기를 들고 있었습니다. 그중 한 사람은 가는 베 옷을 입고 허리에 서기관의 먹 그릇을 차고 있었는데, 이는 특별한 표식을 기록하기 위한 준비였습니다.\n\n하나님께서는 먼저 베 옷을 입은 사람에게 예루살렘 성읍을 순행하며 "그 가운데에서 행하는 모든 가증한 일로 말미암아 탄식하며 우는 자의 이마에 표를 그리라"(겔 9:4)고 명령하십니다. 이 표는 심판 가운데서도 구원받을 자들을 구별하는 인장이었습니다. 죄악으로 가득한 도성에서도 여전히 하나님의 공의를 갈망하며 탄식하는 남은 자들이 있었던 것입니다.\n\n표시가 끝난 후, 나머지 다섯 명의 집행자들에게는 무서운 명령이 내려집니다. 늙은 자와 젊은 자, 처녀와 어린이와 여자를 가리지 않고 모두 죽이되, 오직 이마에 표 있는 자에게는 가까이하지 말라는 것이었습니다. 더욱 충격적인 것은 이 심판이 하나님의 성소에서부터 시작되었다는 점입니다. 성전 앞의 늙은 지도자들부터 심판이 시작된 것은, 하나님께 가장 가까이 있으면서도 가장 큰 책임을 저버린 이들에 대한 엄중한 경고였습니다.\n\n홀로 남겨진 에스겔은 엎드려 부르짖으며 이스라엘의 남은 자마저 멸하시려는지 간구합니다. 그러나 하나님의 대답은 단호했습니다. 이스라엘과 유다의 죄악이 너무나 무거워 땅에는 피가 가득하고 성읍에는 불법이 찼으며, 백성들은 "여호와께서 이 땅을 버리셨으며 여호와께서 보지 아니하신다"고 말하며 더욱 악을 행했다는 것입니다. 하나님의 오래 참으심을 무시하고 그분의 임재를 부인한 결과가 이렇게 무서운 심판으로 나타난 것입니다.\n\n이 환상은 하나님의 심판이 무차별적이지 않음을 보여줍니다. 죄악 가운데서도 의를 갈망하며 탄식하는 자들을 하나님은 기억하시고 보호하십니다. 동시에 하나님과 가장 가까운 곳에서 섬기는 자들이 더 큰 책임을 지고 있음을 엄중히 경고합니다.', E'오늘의 핵심\n하나님은 심판 가운데서도 죄악을 슬퍼하며 탄식하는 자들을 구별하여 보호하시지만, 성전에서 섬기면서도 불의를 행한 자들부터 엄격히 심판하십니다.\n\n묵상 질문\n1. 내 주변의 불의와 죄악을 보며 진정으로 탄식하고 있나요, 아니면 무감각해졌나요?\n2. 하나님과 가까이 있다고 생각하면서도 놓치고 있는 나의 책임은 무엇일까요?\n3. 하나님의 임재를 의심하거나 무시하며 살아가고 있지는 않은가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-07', E'예루살렘의 죄악과 심판 (에스겔 10장)', E'에스겔 10장', E'에스겔이 다시 보게 된 환상은 그발 강가에서 보았던 그 영광스러운 광경이었습니다. 그룹들과 바퀴, 그리고 그 위에 계신 하나님의 보좌가 여전히 그 위엄을 드러내고 있었지만, 이번에는 전혀 다른 목적으로 나타났습니다. 가는 베 옷을 입은 천사에게 하나님께서 명하신 것은 그룹들 사이에 있는 숯불을 가져다가 예루살렘 성읍 위에 흩으라는 것이었습니다. 이는 곧 다가올 심판의 불길을 예고하는 상징적 행위였습니다.\n\n그런데 더욱 충격적인 장면이 이어집니다. 여호와의 영광이 성전 문지방을 떠나 그룹들 위로 옮겨가고, 마침내 성전의 동문으로 이동하는 모습이 상세히 묘사됩니다. 이스라엘의 역사에서 성전은 하나님의 임재를 상징하는 가장 거룩한 장소였습니다. 솔로몬이 성전을 봉헌할 때 구름이 가득 차 제사장들이 서서 섬기지 못할 정도로 하나님의 영광이 충만했던 바로 그 성전에서, 이제는 정반대의 일이 일어나고 있었습니다. 하나님의 영광이 단계적으로 성전을 떠나가는 것입니다.\n\n에스겔은 이 장면을 목격하면서 그룹들의 모습을 더욱 자세히 관찰합니다. 네 얼굴을 가진 그룹들과 눈이 가득한 바퀴들, 그리고 생물의 영이 바퀴 가운데 있어 일체가 되어 움직이는 모습은 하나님의 절대 주권과 전지전능하심을 보여줍니다. 그러나 이 영광스러운 존재들이 이제는 심판의 도구가 되어 예루살렘을 떠날 준비를 하고 있었습니다. 백성들의 거듭된 우상숭배와 불순종으로 인해 하나님께서는 더 이상 그들 가운데 거하실 수 없었던 것입니다. "여호와의 영광이 성전 문지방을 떠나서 그룹들 위에 머무르니"(겔 10:18)라는 구절은 이스라엘 역사상 가장 비극적인 순간을 담담히 전해주고 있습니다.', E'오늘의 핵심\n하나님의 영광이 백성들의 죄악으로 인해 성전을 떠나가는 비극적 순간을 통해, 거룩함을 잃어버린 종교와 형식적 예배의 무의미함을 보여줍니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 임재가 희미해진 영역은 어디인가요?\n2. 형식적인 신앙생활로 인해 놓치고 있는 하나님의 영광은 무엇일까요?\n3. 하나님께서 떠나가시기 전에 내가 회복해야 할 거룩함은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-08', E'예루살렘의 죄악과 심판 (에스겔 11장)', E'에스겔 11장', E'사로잡혀 온 지도자들이 바벨론에서 절망에 빠져 있을 때, 에스겔은 하나님의 영에 이끌려 환상 중에 예루살렘으로 옮겨집니다. 성전 동문에서 목격한 장면은 충격적이었습니다. 야아사냐와 블라댜를 비롯한 25명의 지도자들이 모여 있었는데, 이들은 백성을 잘못된 길로 인도하는 거짓 평안의 메시지를 전하고 있었습니다. "집 건축할 때가 가깝지 아니한즉 이 성읍은 가마가 되고 우리는 고기가 된다"(겔 11:3)라는 그들의 말은 예루살렘이 가마처럼 안전하며 자신들은 그 안에서 보호받는 고기와 같다는 자만심을 드러냅니다.\n\n하나님께서는 이러한 거짓 안전감에 대해 신랄한 심판의 말씀을 선포하십니다. 아이러니하게도 그들이 죽인 시체들이 진짜 ''고기''가 되고, 정작 그들은 성읍 밖으로 끌려나가 이방인의 손에 심판받게 될 것입니다. 에스겔이 예언하던 중 블라댜가 갑작스레 죽는 충격적인 사건은 하나님의 심판이 얼마나 임박했는지를 생생하게 보여줍니다.\n\n그러나 하나님의 메시지는 심판으로만 끝나지 않습니다. 예루살렘에 남은 자들이 포로로 잡혀간 동포들을 향해 "여호와에게서 멀리 떠나라"고 조롱하지만, 오히려 하나님께서는 흩어진 백성들과 함께하시며 그들에게 ''잠깐 성소''가 되어주신다고 약속하십니다. 더 나아가 그들을 다시 모으시고, 돌같이 굳은 마음을 제거하여 살처럼 부드러운 새 마음을 주시겠다는 놀라운 회복의 약속을 주십니다. 이는 단순한 귀환이 아니라 내면의 근본적인 변화, 곧 새로운 언약 관계의 시작을 의미합니다.\n\n환상이 끝나고 에스겔은 다시 바벨론의 포로들에게로 돌아옵니다. 그가 전해야 할 메시지는 명확했습니다. 예루살렘의 멸망은 피할 수 없지만, 하나님께서는 흩어진 백성들 가운데 계시며 그들을 통해 새로운 미래를 준비하고 계신다는 것입니다.', E'오늘의 핵심\n거짓 평안에 취한 예루살렘 지도자들에게는 심판이, 흩어진 포로들에게는 ''새 마음''의 약속이 주어집니다. 하나님은 심판 가운데서도 회복의 희망을 준비하십니다.\n\n묵상 질문\n1. 내가 의지하고 있는 ''거짓 안전감''은 무엇이며, 하나님은 나에게 어떤 참된 평안을 주시나요?\n2. ''돌 같은 마음''에서 ''살처럼 부드러운 마음''으로의 변화를 위해 내가 버려야 할 것은 무엇일까요?\n3. 하나님께서 어려운 상황 속에서도 나의 ''성소''가 되어주신다는 약속이 오늘 나에게 어떤 위로를 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-09', E'하나님을 배역하는 거짓 선지자들 (에스겔 12장)', E'에스겔 12장', E'하나님께서는 반역하는 백성에게 말씀만이 아닌 행동으로도 말씀하십니다. 에스겔에게 포로의 행장을 꾸리고 낮에는 그것을 밖으로 내놓고, 저물어서는 성벽을 뚫고 어깨에 메고 나가라고 명령하십니다. 이 모든 상징적 행동은 곧 예루살렘에 임할 심판을 미리 보여주는 것이었습니다. 시드기야 왕이 밤중에 성벽을 뚫고 도망가다가 바벨론 군대에게 붙잡혀 눈이 뽑힌 채 바벨론으로 끌려갈 운명을 예고하는 것입니다.\n\n이스라엘 백성은 볼 눈이 있어도 보지 않고 들을 귀가 있어도 듣지 않는 반역하는 족속이었습니다. 그들은 "날이 더디고 모든 묵시가 사라지리라"며 하나님의 예언을 조롱했습니다. 심판의 경고가 당장 이루어지지 않자 하나님의 말씀을 무시하고 안일하게 살아갔던 것입니다. 그러나 하나님은 분명히 선포하십니다. 허탄한 묵시와 아첨하는 복술이 사라지고, 하나님의 말씀은 더 이상 지체되지 않고 반드시 이루어질 것이라고 말입니다.\n\n하나님은 심판 가운데서도 소수의 남은 자를 보존하실 계획을 갖고 계셨습니다. 칼과 기근과 전염병에서 벗어난 이들은 이방인 가운데서 자신들의 가증한 일을 자백하며 하나님을 증거하는 도구가 될 것입니다. 이것이 심판 너머에 있는 하나님의 은혜였습니다. 반역하는 백성을 향한 하나님의 마음은 단순한 진노가 아니라, 그들이 돌이켜 하나님을 알기를 간절히 바라는 아버지의 마음이었습니다.', E'오늘의 핵심\n하나님은 반역하는 백성에게 에스겔의 상징적 행동을 통해 임박한 심판을 보여주시며, 그분의 말씀은 반드시 이루어짐을 선포하십니다.\n\n묵상 질문\n1. 하나님의 경고를 듣고도 "아직 시간이 있다"며 미루고 있는 것은 무엇인가요?\n2. 내 삶에서 하나님의 말씀보다 세상의 소리에 더 귀 기울이고 있지는 않나요?\n3. 심판 중에도 남은 자를 두시는 하나님의 은혜가 오늘 나에게 주는 위로는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-10', E'하나님을 배역하는 거짓 선지자들 (에스겔 13장)', E'에스겔 13장', E'하나님의 말씀이 에스겔을 통해 거짓 선지자들에게 향합니다. 당시 이스라엘에는 하나님의 부르심 없이 자기 마음대로 예언하는 자들이 많았습니다. 그들은 "여호와께서 말씀하셨다"고 외쳤지만, 실제로는 자신의 생각과 욕망을 하나님의 이름으로 포장했을 뿐이었습니다. \n\n하나님께서는 이들을 "황무지에 있는 여우"에 비유하십니다. 여우가 폐허 속을 배회하며 먹이를 찾듯이, 거짓 선지자들은 백성의 절망과 혼란을 이용해 자신의 이익을 추구했습니다. 그들은 성벽의 무너진 틈을 막아 백성을 보호해야 할 책임이 있었지만, 오히려 거짓 평안의 메시지로 백성을 더 큰 위험에 빠뜨렸습니다.\n\n특히 하나님께서는 이들의 거짓 예언을 "회칠한 담"에 비유하십니다. 겉으로는 깨끗하고 견고해 보이지만 실제로는 금방 무너질 수밖에 없는 담입니다. 거짓 선지자들은 "평강이 없으나 평강이 있다"고 선포하며 백성을 안심시켰지만, 하나님의 심판이 폭풍우처럼 몰아치면 그들의 거짓말은 모두 드러나고 말 것입니다.\n\n더욱 심각한 것은 여선지자들의 행태였습니다. 그들은 부적과 수건으로 사람들의 영혼을 사냥했습니다. "두어 움큼 보리와 두어 조각 떡"이라는 보잘것없는 대가를 위해 생명과 죽음에 관한 거짓말을 퍼뜨렸습니다. 의인의 마음을 상하게 하고 악인이 회개하지 못하도록 막았습니다.\n\n그러나 하나님께서는 이 모든 거짓을 끝내실 것이라고 선언하십니다. 거짓 선지자들은 하나님 백성의 공회에서 제외되고, 이스라엘의 호적에서 지워지며, 약속의 땅에도 들어가지 못할 것입니다. 하나님께서는 그분의 백성을 거짓 선지자들의 손에서 건져내실 것입니다. 이 모든 심판을 통해 하나님께서 궁극적으로 원하시는 것은 단 하나, "내가 여호와인 줄을 너희가 알리라"는 것입니다.', E'오늘의 핵심\n거짓 선지자들은 하나님의 이름으로 자신의 욕망을 포장하며 백성을 미혹시켰지만, 하나님께서는 그들의 거짓을 폭로하시고 참된 말씀으로 백성을 회복시키실 것입니다.\n\n묵상 질문\n1. 오늘날 우리 주변에서 "평안하다, 평안하다" 외치는 거짓된 목소리는 무엇일까요?\n2. 내가 듣고 싶은 말과 하나님께서 주시는 참된 말씀을 어떻게 분별할 수 있을까요?\n3. 하나님의 백성으로서 무너진 곳을 막아서는 중보자의 역할을 감당하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-11', E'하나님을 배역하는 거짓 선지자들 (에스겔 14장)', E'에스겔 14장', E'이스라엘 장로들이 에스겔을 찾아왔지만, 하나님께서는 그들의 마음속을 꿰뚫어 보고 계셨습니다. 겉으로는 하나님의 뜻을 구하러 온 듯했으나, 그들의 마음에는 이미 우상이 자리 잡고 있었습니다. "이 사람들이 자기 우상을 마음에 들이며 죄악의 걸림돌을 자기 앞에 두었으니"(겔 14:3)라는 하나님의 말씀은 그들의 이중적인 모습을 정확히 지적합니다. \n\n하나님께서는 우상을 마음에 품은 채로 하나님께 나아오는 자들에게 그들이 섬기는 우상의 수효대로 보응하시겠다고 선언하십니다. 이는 단순한 형벌의 선언이 아니라, 그들이 선택한 길의 결과를 스스로 거두게 하시는 하나님의 공의로운 심판입니다. 그럼에도 하나님의 마음은 여전히 당신의 백성을 향하고 있었습니다. 심판의 목적은 "이스라엘 족속이 다시는 미혹되어 나를 떠나지 아니하게 하며" 그들을 참된 하나님의 백성으로 회복시키는 데 있었습니다.\n\n특히 주목할 점은 노아, 다니엘, 욥과 같은 의인들이 있다 하더라도 그들의 의로움이 다른 사람을 구원할 수 없다는 엄중한 선언입니다. 각 사람은 자기의 믿음과 행실로 하나님 앞에 서야 합니다. 이는 신앙이 결코 대물림되거나 타인에게 의존할 수 없는 개인적 결단의 문제임을 분명히 보여줍니다. 칼과 기근, 사나운 짐승과 전염병이라는 네 가지 중한 심판이 임할 때, 오직 각자의 공의로만 자기 생명을 건질 수 있다는 말씀은 우리에게 깊은 경각심을 불러일으킵니다.\n\n그러나 하나님의 심판 가운데서도 소망의 빛줄기가 보입니다. 예루살렘에서 피하는 자들이 남아 있을 것이며, 그들을 통해 하나님의 심판이 결코 이유 없이 행해진 것이 아님을 깨닫게 될 것입니다. 하나님의 심판은 파괴가 목적이 아니라 회복을 위한 과정이었던 것입니다.', E'오늘의 핵심\n우상을 마음에 품은 채 하나님께 나아오는 것은 거짓된 신앙이며, 각 사람은 오직 자기의 믿음으로 하나님 앞에 서야 합니다.\n\n묵상 질문\n1. 내 마음속에 하나님보다 더 중요하게 여기는 우상은 없는지 점검해 보셨나요?\n2. 다른 사람의 믿음에 기대지 않고 나만의 진실한 신앙을 갖기 위해 무엇이 필요할까요?\n3. 하나님의 경고와 징계를 통해 회복을 경험한 적이 있다면 나누어 보세요.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-13', E'심판받는 이스라엘 (에스겔 15장)', E'에스겔 15장', E'에스겔 선지자에게 주신 하나님의 말씀은 예루살렘과 유다 백성을 향한 엄중한 심판의 메시지를 담고 있습니다. 하나님께서는 포도나무의 비유를 통해 이스라엘의 현재 상태를 적나라하게 드러내십니다. 포도나무는 원래 열매를 맺어 사람들에게 기쁨을 주는 나무입니다. 그러나 열매를 맺지 못하는 포도나무는 다른 나무들과 달리 목재로서의 가치도 없습니다. 건축 자재로 쓸 수도 없고, 심지어 물건을 걸 못조차 만들 수 없는 쓸모없는 나무가 되어버립니다.\n\n하나님께서는 이스라엘을 택하여 거룩한 백성으로 삼으시고 열방 가운데서 하나님의 영광을 드러내는 열매를 맺기를 기대하셨습니다. 그러나 이스라엘은 그 부르심에 합당한 삶을 살지 못했고, 오히려 우상을 숭배하며 하나님을 배반했습니다. "내가 수풀 가운데에 있는 포도나무를 불에 던질 땔감이 되게 한 것 같이 내가 예루살렘 주민도 그같이 할지라"(겔 15:6)는 말씀은 하나님의 심판이 얼마나 철저할 것인지를 보여줍니다.\n\n특히 주목할 점은 하나님께서 "그들이 그 불에서 나와도 불이 그들을 사르리니"라고 말씀하신 부분입니다. 이는 한 번의 심판으로 끝나지 않고 계속되는 심판을 의미합니다. 바벨론의 1차 포로기를 겪고도 회개하지 않는다면 더 큰 심판이 임할 것임을 경고하고 있습니다. 하나님께서는 이러한 심판을 통해 "내가 여호와인 줄 너희가 알리라"고 말씀하십니다. 심판의 목적이 단순한 형벌이 아니라 하나님을 바로 알고 돌아오게 하려는 사랑의 표현임을 깨닫게 됩니다.\n\n오늘날 우리도 하나님의 포도나무로 부름받았습니다. 우리가 맺어야 할 열매는 무엇인지, 혹시 쓸모없는 땔감이 되어가고 있지는 않은지 돌아보아야 합니다. 하나님의 은혜로 구원받은 우리가 그 은혜에 합당한 열매를 맺으며 살아가는 것이 진정한 감사의 표현입니다.', E'오늘의 핵심\n하나님께서는 열매 맺지 못하는 포도나무의 비유를 통해 이스라엘의 무용함과 다가올 심판을 선포하시며, 그들이 본래의 사명을 잃어버렸음을 지적하십니다.\n\n묵상 질문\n1. 하나님께서 나에게 기대하시는 열매는 무엇이며, 나는 그 열매를 맺고 있나요?\n2. 혹시 내가 하나님의 은혜를 당연하게 여기며 살고 있지는 않나요?\n3. 오늘 나의 삶이 하나님께 기쁨이 되는 포도나무인지, 아니면 땔감에 불과한지 점검해보면 어떨까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-14', E'심판받는 이스라엘 (에스겔 16장)', E'에스겔 16장', E'가나안 땅에서 태어났지만 아무도 돌보지 않아 피투성이로 버려진 갓난아기였던 예루살렘을 하나님께서 발견하시고 살려주셨습니다. 에스겔은 이러한 비유를 통해 예루살렘의 기원과 하나님의 은혜를 생생하게 전달합니다. 하나님은 버려진 이 아기를 단순히 살려주신 것이 아니라, 극진히 돌보시어 아름다운 여인으로 성장시키셨고, 언약의 관계로 맺어주셨습니다. 금과 은으로 장식하시고, 고운 베와 수놓은 옷을 입히시며, 왕후의 지위에까지 오르게 하신 것은 오직 하나님의 일방적인 사랑과 은혜였습니다.\n\n그러나 예루살렘은 하나님께서 주신 아름다움과 명성을 가지고 행음하기 시작했습니다. 하나님께서 주신 금은 장식품으로 우상을 만들고, 하나님의 기름과 향을 우상 앞에 바쳤으며, 심지어 자녀들을 우상에게 제물로 바쳤습니다. 애굽, 앗수르, 바벨론 등 주변 강대국들과 정치적 동맹을 맺으면서 그들의 우상숭배 문화까지 받아들인 예루살렘의 모습은 남편을 배신하고 다른 남자들과 간음하는 아내로 묘사됩니다. 더욱 충격적인 것은 일반 창기와 달리 오히려 값을 주면서까지 우상을 섬겼다는 점입니다.\n\n이제 하나님께서는 예루살렘의 행위에 대한 심판을 선언하십니다. 그들이 의지했던 열방이 오히려 그들을 심판하는 도구가 될 것이며, 그들의 수치가 만천하에 드러날 것입니다. 그러나 이 무서운 심판의 선언 가운데서도 하나님의 마음은 분노보다는 배신당한 사랑의 아픔으로 가득 차 있음을 볼 수 있습니다. "네가 어렸을 때에 벌거벗은 몸이었으며 피투성이가 되어서 발짓하던 것을 기억하지 아니하고"라는 하나님의 탄식은 은혜를 잊어버린 백성을 향한 안타까움을 담고 있습니다.', E'오늘의 핵심\n하나님께서는 버려진 예루살렘을 구원하시고 영화롭게 하셨으나, 그들이 그 은혜를 잊고 우상을 섬긴 것에 대해 심판을 선언하시면서도 여전히 아픈 사랑의 마음을 품고 계십니다.\n\n묵상 질문\n1. 내가 잊고 있는 하나님의 은혜는 무엇이며, 그것을 어떻게 기억할 수 있을까요?\n2. 하나님께서 주신 축복과 재능을 나는 무엇을 위해 사용하고 있나요?\n3. 하나님의 심판 속에서도 드러나는 그분의 사랑을 어떻게 이해할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-15', E'심판받는 이스라엘 (에스겔 17장)', E'에스겔 17장', E'에스겔 선지자는 하나님께서 주신 수수께끼와 비유를 통해 유다의 운명을 선포합니다. 두 마리의 독수리와 포도나무의 비유는 당시 국제 정세 속에서 유다가 처한 상황을 생생하게 보여줍니다. 첫 번째 독수리인 바벨론 왕 느부갓네살이 예루살렘에 와서 여호야긴 왕을 포로로 잡아가고, 그 대신 시드기야를 왕으로 세웠던 역사적 사실이 비유 속에 담겨 있습니다.\n\n하나님께서는 시드기야를 ''옥토에 심어진 포도나무''로 묘사하십니다. 바벨론의 보호 아래서 안전하게 자랄 수 있었던 포도나무였습니다. 그러나 이 포도나무는 첫 번째 독수리와의 언약을 저버리고 두 번째 독수리인 애굽을 향해 뿌리를 뻗고 가지를 돌렸습니다. 시드기야가 바벨론과의 언약을 배반하고 애굽에 군사적 도움을 요청한 것을 가리킵니다.\n\n하나님께서는 이 배신 행위를 단순한 정치적 실책으로 보지 않으셨습니다. "그가 내 맹세를 업신여기고 내 언약을 배반하였은즉"(겔 17:19)이라는 말씀은 시드기야가 바벨론과 맺은 언약이 하나님의 이름으로 맹세한 것임을 보여줍니다. 언약을 배반한 것은 곧 하나님을 배반한 것이었습니다. 그 결과 시드기야는 바벨론에서 비참한 최후를 맞이하게 될 것이라고 선포됩니다.\n\n그러나 하나님의 심판 선언은 절망으로 끝나지 않습니다. 하나님께서는 직접 백향목 꼭대기에서 연한 가지를 꺾어 이스라엘의 높은 산에 심으실 것을 약속하십니다. 이 새로운 나무는 무성하게 자라 모든 새들이 깃들이는 아름다운 백향목이 될 것입니다. 인간의 배신과 실패에도 불구하고 하나님께서는 당신의 백성을 위한 구원 계획을 포기하지 않으셨습니다. 메시아를 통한 새로운 희망의 약속이 어두운 심판의 메시지 가운데 빛나고 있습니다.', E'오늘의 핵심\n하나님께서는 언약을 배반한 시드기야의 운명을 통해 신실함의 중요성을 가르치시며, 동시에 직접 심으실 새로운 가지를 통해 구원의 소망을 약속하십니다.\n\n묵상 질문\n1. 내가 하나님과 사람 앞에서 맺은 약속들을 신실하게 지키고 있나요?\n2. 어려운 상황에서 하나님보다 세상의 힘을 의지하려는 유혹을 받은 적이 있나요?\n3. 실패와 심판 가운데서도 새로운 소망을 심으시는 하나님의 은혜를 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-16', E'심판을 거부하는 이스라엘 (에스겔 18장)', E'에스겔 18장', E'바빌론 포로 생활의 고단함 속에서 이스라엘 백성들 사이에 한 속담이 돌고 있었습니다. "아버지가 신 포도를 먹었으므로 그의 아들의 이가 시다"(겔 18:2)라는 말이었습니다. 이는 자신들이 겪는 고통의 원인을 조상들의 죄에서 찾으며, 현재의 심판이 부당하다고 항변하는 내용이었습니다. 그러나 하나님께서는 이 속담이 더 이상 쓰이지 못할 것이라고 선언하십니다. 모든 영혼이 하나님께 속하였으며, 각 사람은 자신의 행위에 따라 심판받는다는 것이 하나님의 공의로운 원칙임을 분명히 하십니다.\n\n에스겔을 통해 전해지는 하나님의 말씀은 개인의 책임을 강조합니다. 의로운 아버지가 악한 아들을 낳았다면, 그 아들은 자신의 악행으로 인해 죽을 것이며, 악한 아버지가 의로운 아들을 낳았다면, 그 아들은 아버지의 죄로 인해 죽지 않을 것입니다. 하나님께서는 각 사람의 행위를 따라 심판하시되, 의인의 공의는 그에게로, 악인의 악은 그에게로 돌아간다고 말씀하십니다. 이는 단순히 공정한 심판의 원칙만을 선포하는 것이 아니라, 각 개인에게 회개와 변화의 기회가 열려 있음을 보여주는 은혜의 메시지입니다.\n\n특별히 주목할 것은 하나님의 마음입니다. "내가 어찌 악인이 죽는 것을 조금인들 기뻐하랴"(겔 18:23)라는 말씀에서 드러나듯이, 하나님께서는 심판 자체를 원하시는 것이 아니라 죄인이 돌이켜 생명을 얻기를 간절히 원하십니다. 악인이라도 자신의 모든 죄에서 돌이켜 떠나 하나님의 율례를 지키고 정의와 공의를 행하면 반드시 살 것이라는 약속이 주어집니다. 이는 웨슬리가 강조한 선행은총의 역사입니다. 하나님께서는 먼저 은혜를 베푸시고, 인간이 그 은혜에 응답하여 돌이킬 수 있는 능력을 주십니다. "너희는 돌이켜 회개하고 모든 죄에서 떠날지어다"라는 권면은 명령인 동시에, 그렇게 할 수 있는 은혜가 이미 주어졌음을 전제하는 초대입니다.', E'오늘의 핵심\n하나님께서는 각 사람을 그 행위대로 심판하시되, 악인이라도 돌이켜 회개하면 살리시는 은혜의 하나님이십니다.\n\n묵상 질문\n1. 내 삶의 문제를 다른 사람이나 환경 탓으로 돌리고 있지는 않나요?\n2. 하나님께서 악인의 죽음을 기뻐하지 않으신다면, 나는 어떤 마음으로 죄인을 바라보고 있나요?\n3. 오늘 하나님께서 내게 돌이키라고 부르시는 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-17', E'심판을 거부하는 이스라엘 (에스겔 19장)', E'에스겔 19장', E'에스겔 19장은 이스라엘 고관들을 위한 애가(哀歌)입니다. 하나님께서는 에스겔에게 이스라엘 왕가의 비극적 운명을 노래하라고 명하십니다. 이 애가는 두 가지 상징적 그림을 통해 유다 왕국의 몰락을 묘사합니다.\n\n첫 번째 그림은 암사자와 그 새끼들의 이야기입니다. 암사자는 유다 왕국을, 새끼들은 그 왕들을 가리킵니다. 첫 번째 새끼는 여호아하스 왕으로, 그는 애굽으로 끌려갔습니다. 두 번째 새끼는 여호야긴 왕으로, 바벨론에 포로로 잡혀갔습니다. 사자로 묘사된 이 왕들은 힘과 권세를 가졌지만, 결국 이방 나라들에 의해 잡혀가는 비참한 운명을 맞이했습니다.\n\n두 번째 그림은 포도나무의 비유입니다. 물가에 심겨져 풍성한 열매를 맺던 포도나무는 유다 왕국의 번영을 상징합니다. 그러나 "분노 중에 뽑혀서 땅에 던짐을 당하매"(겔 19:12)라는 표현처럼, 하나님의 심판으로 인해 뿌리째 뽑혀 광야에 버려졌습니다. 한때 왕의 규(圭)가 될 만큼 강했던 가지들은 꺾이고 말라 불에 탔습니다. 이는 시드기야 왕 때 예루살렘이 멸망하고 왕조가 끝나는 것을 예언합니다.\n\n이 애가가 특별한 이유는 단순히 과거를 회상하거나 미래를 예언하는 데 그치지 않기 때문입니다. 에스겔은 이미 일어난 일과 곧 일어날 일을 함께 엮어 하나님의 심판이 얼마나 철저한지를 보여줍니다. 왕들의 포로됨과 왕국의 멸망은 우연이나 불운이 아니라, 하나님께서 그들의 죄악에 대해 내리신 정당한 심판이었습니다.\n\n애가의 마지막 구절 "이것이 애가라 후에도 애가가 되리라"는 이 슬픔이 일시적이지 않음을 암시합니다. 그러나 성경 전체의 맥락에서 볼 때, 하나님의 심판은 결코 끝이 아닙니다. 심판 너머에는 언제나 회복의 소망이 있습니다. 다윗의 보좌는 무너졌지만, 그 줄기에서 새로운 가지가 나실 것입니다. 이것이 바로 메시아를 통한 구원의 약속입니다.', E'오늘의 핵심\n하나님께서는 이스라엘 왕가의 몰락을 애가로 노래하게 하심으로써, 그들의 멸망이 하나님의 정당한 심판임을 선포하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 경고와 징계를 무시하고 있는 영역은 없나요?\n2. 세상의 권세와 힘을 의지하다가 무너진 왕들의 모습이 오늘날 우리에게 주는 교훈은 무엇일까요?\n3. 심판 가운데서도 소망을 잃지 않는 믿음을 어떻게 지킬 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-18', E'심판을 거부하는 이스라엘 (에스겔 20장)', E'에스겔 20장', E'포로로 끌려온 지 7년째 되던 해, 이스라엘의 장로들이 에스겔을 찾아와 하나님의 뜻을 묻고자 했습니다. 그러나 하나님께서는 그들의 물음을 단호히 거절하시며, 오히려 그들 조상들의 죄악의 역사를 낱낱이 드러내라고 명하십니다. 이스라엘의 패역함은 애굽에서부터 시작되었습니다. 하나님께서 그들을 택하시고 젖과 꿀이 흐르는 땅으로 인도하겠다고 약속하셨으나, 그들은 애굽의 우상들을 버리지 않았습니다.\n\n광야에서도 마찬가지였습니다. 하나님께서는 생명을 주는 율례와 규례를 주시고, 안식일을 거룩하게 하는 표징으로 삼으셨습니다. 그러나 이스라엘은 율례를 멸시하고 안식일을 더럽혔습니다. 하나님께서는 진노하셨지만 자신의 이름을 위하여 그들을 멸하지 않으셨습니다. 이방인들이 보는 앞에서 하나님의 이름이 욕되지 않게 하려는 거룩한 열심 때문이었습니다.\n\n더욱 안타까운 것은 광야에서 자란 2세대도 동일한 죄를 반복했다는 점입니다. 하나님께서는 그들에게 조상의 악한 길을 따르지 말라고 경고하셨으나, 그들 역시 우상을 따르며 안식일을 더럽혔습니다. 약속의 땅에 들어간 후에는 더욱 심각해져서, 모든 높은 산과 무성한 나무 아래에서 제사를 드리며 심지어 자녀를 불 가운데로 지나게 하는 가증한 일까지 행했습니다.\n\n이제 포로로 잡혀온 상황에서도 그들은 여전히 "우리가 이방인처럼 목석을 경배하리라"라고 말합니다. 그러나 하나님께서는 능한 손과 편 팔로 그들을 다스리시겠다고 선포하십니다. 흩어진 백성을 다시 모으시되, 광야의 심판을 통해 정결케 하신 후에야 약속의 땅으로 인도하시겠다는 것입니다. 이는 심판 속에서도 포기하지 않으시는 하나님의 신실하심을 보여줍니다.', E'오늘의 핵심\n하나님께서는 이스라엘의 반복되는 우상숭배의 역사를 드러내시며, 그럼에도 불구하고 자신의 이름을 위하여 그들을 포기하지 않으시고 능한 손으로 다스리실 것을 약속하십니다.\n\n묵상 질문\n1. 나의 신앙생활에서 반복되는 실패의 패턴은 무엇이며, 그것을 끊기 위해 어떤 결단이 필요할까요?\n2. 하나님께서 자신의 이름을 위하여 인내하신다는 것이 나에게 어떤 위로와 도전이 되나요?\n3. 하나님의 능한 손과 편 팔로 다스리심을 받는다는 것은 무엇을 의미하며, 나는 그 다스림에 순종할 준비가 되어 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-20', E'심판받는 이스라엘 (에스겔 21장)', E'에스겔 21장', E'여호와의 말씀이 에스겔에게 임하여 예루살렘을 향한 심판의 메시지를 전하게 하십니다. 하나님께서는 칼을 칼집에서 빼어 의인과 악인을 끊으시겠다고 선포하시는데, 이는 이스라엘이 끊임없이 하나님을 배역하고 우상을 숭배하며 불의를 행했기 때문입니다. 특히 "칼아 모이라 오른쪽을 치라 대열을 맞추라 왼쪽을 치라 향한 대로 가라"(겔 21:16)는 말씀은 하나님의 심판 도구인 바벨론이 얼마나 철저하게 예루살렘을 공격할 것인지를 보여줍니다.\n\n에스겔은 허리가 끊어지듯 탄식하라는 명령을 받습니다. 이는 단순한 슬픔의 표현이 아니라, 다가올 재앙의 참혹함을 백성들에게 미리 보여주는 예언적 행동이었습니다. 날카롭고 빛나는 칼의 이미지는 바벨론 군대의 무자비한 공격을 상징하며, 이스라엘의 왕과 고관들까지도 피할 수 없는 완전한 심판을 예고합니다.\n\n흥미로운 것은 바벨론 왕이 갈랫길에서 점을 쳐서 예루살렘으로 가는 길을 택하는 장면입니다. 인간의 눈에는 우연한 선택처럼 보이지만, 실상은 하나님께서 주권적으로 역사를 이끌어 가시는 모습을 보여줍니다. 바벨론 왕은 자신의 뜻대로 행한다고 생각하지만, 그 모든 과정이 하나님의 계획 안에서 이루어지고 있었던 것입니다.\n\n하나님은 높은 자를 낮추시고 낮은 자를 높이시는 분이십니다. 예루살렘의 왕관이 벗겨지고 영광이 사라지는 것은 그들이 하나님의 정의를 버리고 자신들의 욕심을 따랐기 때문입니다. 그러나 심판 가운데서도 소망의 빛이 비칩니다. "마땅히 얻을 자가 이르면 그에게 주리라"는 말씀은 장차 오실 메시아를 암시하며, 하나님의 구원 계획이 심판 너머에 있음을 보여줍니다.', E'오늘의 핵심\n하나님께서는 끝까지 회개하지 않는 예루살렘에 대해 바벨론을 통한 철저한 심판을 선포하시며, 이 모든 과정이 하나님의 주권적 통치 아래 있음을 보여주십니다.\n\n묵상 질문\n1. 하나님의 심판이 의인과 악인을 함께 끊는다는 말씀이 나에게 주는 경고는 무엇일까요?\n2. 오늘 내 삶에서 하나님의 주권적 인도하심을 어떻게 경험하고 있나요?\n3. 심판 중에도 구원의 소망을 품으신 하나님의 마음을 묵상할 때 어떤 감사가 생기나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-21', E'심판받는 이스라엘 (에스겔 22장)', E'에스겔 22장', E'하나님께서는 에스겔을 통해 예루살렘을 "피흘린 성읍"으로 부르시며 그들의 죄악을 낱낱이 드러내십니다. 한때 거룩한 도성이었던 예루살렘이 이제는 온갖 죄악으로 가득한 곳이 되어버렸습니다. 하나님께서 열거하시는 죄목들은 참으로 충격적입니다. 권력자들은 각기 권세를 이용해 피를 흘렸고, 백성들은 부모를 업신여기고 나그네와 고아와 과부를 학대했습니다. 거룩한 것을 업신여기고 안식일을 더럽혔으며, 온갖 성적 타락과 뇌물, 고리대금업으로 이웃을 착취했습니다.\n\n특별히 하나님의 마음을 아프게 한 것은 영적 지도자들의 타락이었습니다. 선지자들은 거짓을 전하며 백성의 영혼을 삼켰고, 제사장들은 하나님의 율법을 범하고 거룩한 것과 속된 것을 구별하지 않았습니다. 고관들은 불의한 이익을 위해 피를 흘렸습니다. 하나님께서는 이들을 풀무 속의 찌꺼기에 비유하시며, 정련의 불로 심판하실 것을 선포하십니다.\n\n가장 가슴 아픈 구절은 30절입니다. "이 땅을 위하여 성을 쌓으며 성 무너진 데를 막아 서서 나로 하여금 멸하지 못하게 할 사람을 내가 그 가운데에서 찾다가 찾지 못하였으므로." 하나님께서는 심판하기 원치 않으셨습니다. 단 한 사람이라도 중보자로 서서 기도하기를 바라셨지만, 그런 사람을 찾을 수 없었던 것입니다. 이것이 예루살렘 멸망의 결정적 이유였습니다. 죄악이 관영했을 뿐 아니라, 그 죄악의 틈새를 막아설 의인이 단 한 명도 없었던 것입니다.', E'오늘의 핵심\n하나님께서는 예루살렘의 총체적 타락상을 폭로하시며, 특히 영적 지도자들의 실패와 중보자의 부재가 심판을 피할 수 없게 만들었음을 보여주십니다.\n\n묵상 질문\n1. 오늘날 우리 사회와 교회 안에서 하나님께서 지적하실 만한 죄악은 무엇일까요?\n2. 하나님께서 나를 이 시대의 중보자로 부르신다면, 나는 어떻게 응답하겠습니까?\n3. 영적 지도자들의 타락이 공동체에 미치는 영향을 보며 무엇을 느끼십니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-22', E'사마리아와 예루살렘에 임한 심판 (에스겔 23장)', E'에스겔 23장', E'하나님께서는 예루살렘의 죄악을 더욱 생생하게 드러내시기 위해 두 자매의 비유를 사용하십니다. 형 오홀라는 북이스라엘의 수도 사마리아를, 동생 오홀리바는 남유다의 수도 예루살렘을 가리킵니다. 이 두 자매는 애굽에서부터 우상숭배라는 영적 간음을 시작했으며, 약속의 땅에 들어온 후에도 계속해서 주변 강대국들을 의지하며 그들의 우상을 섬겼습니다.\n\n오홀라는 앗수르를 사모하여 그들과 동맹을 맺고 그들의 신을 받아들였지만, 결국 기원전 722년 앗수르에 의해 멸망당했습니다. 하나님께서는 이를 통해 남유다에게 분명한 경고를 주셨습니다. 그러나 오홀리바 예루살렘은 형의 비참한 최후를 목격하고도 회개하기는커녕 오히려 더 심한 우상숭배에 빠져들었습니다. 앗수르뿐 아니라 바벨론의 화려한 문화에 매료되어 그들과 동맹을 맺었다가, 다시 그들을 배신하고 애굽을 의지하는 변덕스러운 모습을 보였습니다.\n\n하나님께서는 이러한 예루살렘의 행태를 "네가 젊었을 때에 행음하여 애굽 사람에게 네 가슴과 유방이 어루만져졌던 것을 아직도 생각하도다"(겔 23:21)라고 묘사하시며, 그들이 하나님과의 언약 관계를 얼마나 가볍게 여겼는지를 드러내십니다. 결국 예루살렘도 그들이 의지했던 바벨론에 의해 멸망당할 것이며, 이는 하나님의 공의로운 심판임을 선포하십니다.\n\n이 비유는 단순히 정치적 동맹의 문제가 아니라, 하나님을 떠나 세상의 힘과 문화를 의지하는 영적 간음의 본질을 보여줍니다. 하나님께서는 자기 백성이 오직 당신만을 신뢰하고 의지하기를 원하시지만, 이스라엘은 끊임없이 눈에 보이는 세상의 화려함에 마음을 빼앗겼습니다. 그럼에도 불구하고 이 엄중한 심판 선언 가운데서도 하나님의 아픔과 안타까움이 배어 있음을 우리는 놓치지 말아야 합니다.', E'오늘의 핵심\n하나님께서는 두 자매의 비유를 통해 이스라엘의 영적 간음, 곧 하나님을 떠나 세상 권력과 우상을 의지한 죄의 심각성을 드러내시고 심판을 선언하십니다.\n\n묵상 질문\n1. 내가 하나님보다 더 의지하고 있는 세상의 힘이나 가치는 무엇인가요?\n2. 다른 사람의 실패를 보면서도 같은 길을 반복하는 이유는 무엇일까요?\n3. 하나님과의 언약 관계를 가볍게 여기는 내 모습은 없는지 점검해 보시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-23', E'사마리아와 예루살렘에 임한 심판 (에스겔 24장)', E'에스겔 24장', E'포위된 지 2년째, 바벨론의 공격이 본격화되던 때에 하나님께서는 에스겔에게 특별한 메시지를 주십니다. 끓는 가마의 비유를 통해 예루살렘의 운명을 보여주신 것입니다. 가마 속의 좋은 고기 덩어리들은 예루살렘의 지도자들을 가리키며, 그들이 뜨거운 불 속에서 삶아지듯 심판받을 것을 예고합니다. 특히 이 가마는 녹이 슬어 있는데, 그 녹은 예루살렘에 쌓인 죄악을 상징합니다. 아무리 끓여도 녹이 벗겨지지 않듯이, 예루살렘의 죄악도 쉽게 씻겨지지 않을 것입니다.\n\n더욱 충격적인 것은 하나님께서 에스겔의 아내를 데려가시면서 슬퍼하지 말라고 명하신 일입니다. 사랑하는 아내의 죽음 앞에서도 애곡하지 못하고 조용히 탄식만 해야 했던 에스겔의 모습은, 곧 닥칠 예루살렘의 비극을 미리 보여주는 표징이었습니다. 백성들이 가장 자랑스러워하던 성전이 무너지고 자녀들이 칼에 쓰러질 때, 그들은 슬퍼할 겨를도 없이 충격에 빠져 서로를 바라보며 탄식만 할 것입니다.\n\n에스겔의 상징적 행동은 하나님께서 주시는 메시지를 더욱 뚜렷하게 전달해 주고 있습니다. 심판의 날이 임했을 때 백성들은 비로소 하나님의 경고가 진실이었음을 깨닫게 될 것입니다. 그러나 그때는 이미 회개하기에 너무 늦은 시점입니다. 하나님께서는 반복된 경고에도 불구하고 돌이키지 않는 백성들에게 마지막 심판을 선언하시면서도, 에스겔을 통해 당신이 참 하나님이심을 알게 하려는 목적을 분명히 하십니다. 심판 속에서도 하나님의 주권과 공의를 드러내시는 것입니다.', E'오늘의 핵심\n하나님께서는 끓는 가마의 비유와 에스겔 아내의 죽음을 통해 예루살렘에 임할 피할 수 없는 심판을 생생하게 보여주셨습니다.\n\n묵상 질문\n1. 반복된 경고에도 회개하지 않는 내 마음의 완고함은 없는지 돌아볼까요?\n2. 하나님의 심판이 임하기 전에 지금 내가 돌이켜야 할 것은 무엇일까요?\n3. 고통스러운 상황 속에서도 하나님의 뜻을 전하는 에스겔처럼, 나는 어떤 순종을 드려야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-24', E'이스라엘 주변 민족에 대한 심판 (에스겔 25장)', E'에스겔 25장', E'포로로 잡혀간 에스겔에게 하나님의 말씀이 임합니다. 이번에는 이스라엘 주변 나라들을 향한 심판의 메시지였습니다. 남유다가 바벨론의 침략을 받아 멸망의 위기에 처했을 때, 주변 나라들은 이를 기회로 여기며 조롱하고 약탈하려 했습니다. 그러나 하나님께서는 이들의 악행을 그냥 지나치지 않으셨습니다.\n\n먼저 암몬 족속에 대한 심판이 선포됩니다. 그들은 예루살렘 성전이 더럽혀지고 유다 백성이 포로로 잡혀갈 때 "아하 좋다"라고 조롱했습니다. 하나님의 백성이 고난당하는 것을 보며 기뻐한 그들에게, 하나님께서는 동방 민족들에게 정복당하여 노략을 당하게 될 것이라고 선언하십니다. 수도 랍바는 낙타의 우리가 되고, 그들의 땅은 양떼가 눕는 곳이 될 것입니다.\n\n모압과 세일도 심판을 피할 수 없었습니다. 그들은 "유다 족속은 모든 이방과 다름이 없다"고 말하며 하나님의 선택받은 백성을 무시했습니다. 이에 하나님께서는 모압의 국경 도시들을 열어 동방 사람들에게 넘겨주실 것을 선포하십니다.\n\n에돔은 형제 나라인 유다를 공격하여 원수를 갚았습니다. 야곱과 에서의 후손으로서 혈연관계였음에도 불구하고, 유다가 어려움에 처했을 때 도움은커녕 오히려 공격한 것입니다. 하나님께서는 데만에서 드단까지 에돔 전 지역을 황폐하게 하실 것을 선언하십니다.\n\n블레셋은 옛날부터 이스라엘을 미워하여 기회만 있으면 공격했습니다. 멸시하는 마음으로 원수를 갚고자 했던 그들에게도 하나님의 심판이 임할 것입니다. 그렛 사람들과 해변에 거주하는 자들이 진멸당할 것입니다.\n\n이 모든 심판 선언의 목적은 분명합니다. "내가 여호와인 줄을 너희가 알리라"는 말씀이 반복되는 것처럼, 하나님께서는 이스라엘뿐 아니라 모든 민족의 주권자이심을 나타내고자 하셨습니다. 남의 불행을 기뻐하고 약자를 괴롭히는 것은 결국 하나님의 공의로운 심판을 자초하는 일임을 보여주고 있습니다.', E'오늘의 핵심\n하나님께서는 자기 백성의 고난을 조롱하고 기뻐했던 주변 나라들에게 공의로운 심판을 선포하시며, 모든 민족의 주권자이심을 분명히 하십니다.\n\n묵상 질문\n1. 다른 사람의 어려움을 보며 은근히 기뻐했던 적은 없었나요?\n2. 하나님께서는 왜 이스라엘뿐 아니라 주변 나라들도 심판하실까요?\n3. "내가 여호와인 줄 알리라"는 말씀이 나에게 주는 의미는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-25', E'이스라엘 주변 민족에 대한 심판 (에스겔 26장)', E'에스겔 26장', E'다윗과 솔로몬 시대에 이스라엘과 우호적 관계를 유지하며 성전 건축에 큰 도움을 주었던 두로가 이제는 하나님의 심판 대상이 되었습니다. 지중해 연안의 항구도시 두로는 탁월한 해상무역으로 막대한 부를 축적했고, 그 부가 가져다준 힘과 영향력을 자랑하며 살았습니다. 그런데 무역 경쟁국이었던 예루살렘이 바벨론에게 함락되자, 두로는 이를 조롱하며 기뻐했습니다. "아하 만민의 문이 깨져서 내게로 돌아왔도다"(겔 26:2)라는 그들의 외침은 예루살렘의 멸망이 자신들에게 경제적 이익을 가져다줄 것이라는 계산에서 나온 것이었습니다.\n\n하나님께서는 두로의 이러한 태도에 대해 엄중한 심판을 선언하십니다. 바다가 파도를 굽이치게 하듯 여러 민족들이 두로를 치게 하실 것이며, 특별히 바벨론 왕 느부갓네살을 통해 그 심판을 이루실 것이라고 말씀하십니다. 한때 견고했던 성벽과 망대는 무너지고, 화려했던 도시는 맨 바위가 되어 그물을 말리는 곳으로 전락할 것입니다. 노래 소리와 수금 소리가 그치고, 다시는 재건되지 못할 것이라는 선언은 두로의 완전한 멸망을 예고합니다.\n\n이 예언의 말씀은 역사 속에서 그대로 성취되었습니다. 느부갓네살의 13년간의 포위 공격과 이후 알렉산더 대왕의 정복으로 두로는 철저히 파괴되었고, 한때 지중해의 여왕으로 불리던 그 영광은 사라졌습니다. 하나님께서는 이스라엘만의 하나님이 아니라 온 세계와 역사를 주관하시는 분이심을 두로의 심판을 통해 분명히 보여주고 계십니다. 남의 불행을 기뻐하고 자신의 부와 힘만을 의지했던 두로의 운명은, 하나님을 떠난 교만이 어떤 결과를 가져오는지를 엄중하게 경고합니다.', E'오늘의 핵심\n한때 이스라엘의 동맹국이었던 두로가 예루살렘의 멸망을 기뻐하며 경제적 이익을 계산했을 때, 하나님께서는 그들의 교만과 무정함에 대해 완전한 멸망으로 심판하십니다.\n\n묵상 질문\n1. 남의 어려움이 나에게 이익이 될 것이라고 계산하며 기뻐한 적은 없나요?\n2. 물질적 풍요와 성공이 가져다주는 교만의 위험을 어떻게 경계할 수 있을까요?\n3. 하나님께서 모든 나라와 민족의 역사를 주관하신다는 사실이 내게 주는 교훈은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-27', E'이스라엘 주변 민족에 대한 심판 (에스겔 27장)', E'에스겔 27장', E'지중해 연안의 부유한 항구 도시 두로를 향한 하나님의 심판이 선포됩니다. 에스겔은 두로를 화려한 무역선에 비유하여 그들의 영광과 몰락을 동시에 보여줍니다. 두로는 "나는 온전히 아름답다"(겔 27:3)라고 스스로를 자랑했습니다. 실제로 두로는 당대 최고의 무역 중심지였고, 지중해 전역과 거래하며 막대한 부를 축적했습니다. \n\n에스겔은 두로의 화려함을 배의 건조 과정과 운영으로 세밀하게 묘사합니다. 최고급 목재들로 선체와 돛대를 만들고, 이집트의 수놓은 베로 돛을 달았으며, 상아로 갑판을 장식했습니다. 시돈과 아르왓의 숙련된 사공들이 배를 운전하고, 각국의 용사들이 호위했습니다. 다시스에서 은과 철이, 야완에서 노예들이, 아라비아에서 가축들이, 스바에서 향료와 보석이 거래되었습니다. 이스라엘도 밀과 꿀과 기름으로 두로와 교역했습니다.\n\n그러나 하나님께서는 이 거대한 무역선이 동풍에 의해 바다 한가운데서 침몰할 것이라고 선포하십니다. 축적된 모든 재물과 상품, 선원들과 상인들이 함께 바다에 빠져 사라질 것입니다. 두로의 파멸을 목격한 주변 나라들은 충격에 빠지고, 그들과 거래하던 상인들은 비웃을 것입니다. \n\n두로의 심판은 단순히 한 도시의 멸망 이상의 의미를 담고 있습니다. 물질적 풍요와 경제력을 자랑하며 스스로를 높인 교만이 그들을 멸망으로 이끌었습니다. 하나님께서는 인간의 성취와 부가 아무리 대단해도 그분의 주권 앞에서는 한순간에 무너질 수 있음을 보여주십니다.', E'오늘의 핵심\n물질적 풍요를 의지하며 교만해진 두로는 하나님의 심판으로 바다 한가운데서 침몰하는 배처럼 완전히 파멸하게 됩니다.\n\n묵상 질문\n1. 내가 의지하는 것들이 한순간에 사라진다면 나는 어떤 존재로 남을까요?\n2. 경제적 성공이나 물질적 풍요가 나를 교만하게 만들고 있지는 않나요?\n3. 하나님의 주권을 인정하며 겸손히 살아가려면 어떤 결단이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-28', E'이스라엘 주변 민족에 대한 심판 (에스겔 28장)', E'에스겔 28장', E'에스겔 28장은 두로 왕의 교만과 멸망, 그리고 시돈에 대한 심판을 선포하며 하나님의 주권을 드러냅니다. 두로 왕은 자신의 지혜와 무역으로 축적한 부를 근거로 스스로를 신이라 칭하며 "나는 신이라 내가 하나님의 자리 곧 바다 가운데에 앉아 있다"(겔 28:2)고 선언합니다. 그의 지혜는 다니엘보다 뛰어나다고 자부했고, 무역을 통해 금과 은을 곳간에 쌓았습니다. 그러나 하나님께서는 그가 사람일 뿐 신이 아님을 분명히 하십니다.\n\n특별히 주목할 것은 두로 왕을 향한 슬픈 노래입니다. 하나님께서는 두로 왕이 한때 에덴동산에서 각종 보석으로 단장되고 기름 부음을 받은 그룹이었다고 묘사하십니다. 그는 하나님의 성산에서 불타는 돌들 사이를 왕래하며 창조된 날부터 완전했습니다. 그러나 무역이 번성하면서 그의 마음에 강포가 가득해졌고, 아름다움 때문에 교만해져서 지혜를 더럽혔습니다. 결국 하나님께서는 그를 성산에서 쫓아내시고 땅에 던져 재가 되게 하셨습니다.\n\n시돈에 대한 심판도 이어집니다. 하나님께서는 전염병과 칼로 시돈을 치실 것을 선포하십니다. 이 모든 심판을 통해 하나님께서는 당신의 거룩함을 나타내시고, 이스라엘을 멸시하던 가시 같은 존재들을 제거하실 것입니다. \n\n놀라운 것은 심판 선포 후에 주어지는 회복의 약속입니다. 흩어진 이스라엘 백성을 다시 모으시고, 야곱에게 주신 땅에서 평안히 거주하게 하실 것입니다. 그들은 집을 건축하고 포도원을 만들며 평화롭게 살 것입니다. 이는 교만한 자들은 멸망하지만, 하나님의 백성은 결국 회복된다는 소망의 메시지입니다.', E'오늘의 핵심\n하나님께서는 인간의 교만을 용납하지 않으시며, 스스로 신이 되려는 모든 시도를 심판하시지만, 동시에 당신의 백성을 위한 회복의 계획을 잊지 않으십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 자리를 차지하려는 교만한 마음은 없나요?\n2. 물질적 성공이 영적 타락으로 이어지지 않으려면 어떻게 해야 할까요?\n3. 하나님의 심판 가운데서도 회복의 소망을 품을 수 있는 이유는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-29', E'애굽에 대한 심판 (에스겔 29장)', E'에스겔 29장', E'포로 생활 열 번째 해가 되었을 때, 하나님께서는 에스겔을 통해 애굽에 대한 심판을 선포하십니다. 당시 애굽은 고대 근동의 강대국으로서 많은 나라들이 의지하려 했던 나라였습니다. 남유다 역시 바벨론의 위협 앞에서 하나님보다는 애굽의 군사력을 의지하려 했습니다. 그러나 하나님께서는 애굽의 교만한 바로를 "자기의 강들 가운데에 누운 큰 악어"로 묘사하시며 그들의 멸망을 예고하십니다.\n\n애굽 왕 바로의 교만은 극에 달해 있었습니다. 그는 "나의 이 강은 내 것이라 내가 나를 위하여 만들었다"고 선언합니다. 나일강의 풍요로움이 애굽 문명의 기초가 되었지만, 바로는 그 모든 것이 자신의 능력으로 이루어진 것처럼 여겼습니다. 창조주 하나님을 인정하지 않고 자신을 신격화하는 바로의 모습은 하나님의 심판을 자초하는 것이었습니다.\n\n하나님께서는 갈고리로 악어를 낚듯이 애굽을 끌어내어 들에 던지실 것이라고 선언하십니다. 더욱이 애굽은 이스라엘에게 "갈대 지팡이"와 같았다고 말씀하십니다. 겉으로는 든든해 보이지만 실제로 기댔을 때는 부러져서 오히려 상처만 입히는 존재였던 것입니다. 이것은 하나님을 신뢰하지 않고 세상의 힘을 의지했던 이스라엘 백성들에게 주시는 뼈아픈 교훈이었습니다.\n\n그러나 하나님의 심판 가운데서도 회복의 소망이 보입니다. 애굽이 40년간 황폐하게 된 후 다시 모여질 것이며, 비록 미약한 나라가 되지만 완전히 멸망하지는 않을 것이라는 약속입니다. 이는 하나님의 심판이 단순한 파괴가 아니라 교만을 꺾고 하나님을 인정하도록 하시는 징계임을 보여줍니다. 느부갓네살을 통한 애굽 정벌도 결국 "내가 여호와인 줄을 그들이 알리라"는 하나님의 궁극적인 목적을 이루기 위한 것이었습니다.', E'오늘의 핵심\n하나님께서는 교만한 애굽을 심판하심으로써 이스라엘과 열방이 참된 의지처는 오직 여호와 하나님이심을 깨닫게 하십니다.\n\n묵상 질문\n1. 내가 이룬 성취를 하나님의 은혜가 아닌 내 능력으로 여긴 적은 없나요?\n2. 하나님보다 세상의 힘과 방법을 더 의지하고 있는 영역은 무엇인가요?\n3. 하나님의 징계 속에서도 회복의 소망을 발견할 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-30', E'애굽에 대한 심판 (에스겔 30장)', E'에스겔 30장', E'하나님께서는 에스겔을 통해 애굽에 임할 재앙의 날을 선포하십니다. "구름의 날"이라 불리는 그날은 단지 애굽만이 아니라 여러 나라들에게 심판의 때가 될 것입니다. 애굽과 동맹을 맺은 구스, 붓, 룻을 비롯한 주변 나라들도 함께 멸망할 것이라는 경고는 세상의 힘을 의지하는 것이 얼마나 허망한지를 보여줍니다.\n\n특히 하나님께서는 애굽의 우상들과 신상들을 부수시고, 다시는 애굽 땅에서 왕이 나지 못하게 하시겠다고 선언하십니다. 나일강의 풍요를 자랑하던 애굽의 주요 도시들 - 놉, 소안, 신, 아웬, 비베셋, 드합느헤스 - 은 모두 파괴되고 그 주민들은 포로가 될 것입니다. 애굽이 자랑하던 "교만한 권세"는 완전히 꺾일 것입니다.\n\n바로 왕의 팔을 꺾으시는 하나님의 심판은 매우 상징적입니다. 이미 한 팔이 꺾였는데도 제대로 치료하지 못한 바로는, 이제 성한 팔마저 꺾여 더 이상 칼을 잡을 수 없게 됩니다. 반면 바벨론 왕의 팔은 견고해지고 하나님의 칼을 받아 애굽을 치게 됩니다. 이는 하나님께서 역사의 주관자로서 열방을 다스리시며, 교만한 자를 낮추시고 당신의 도구로 사용하실 자를 높이신다는 것을 보여줍니다.\n\n하나님께서는 이 모든 심판을 통해 "내가 여호와인 줄을 그들이 알리라"고 반복하여 말씀하십니다. 애굽의 멸망은 단순한 정치적 사건이 아니라, 온 세상의 참된 주권자가 누구인지를 만방에 알리시는 하나님의 계시적 행동입니다. 세상의 힘과 우상을 의지하던 애굽이 무너질 때, 비로소 사람들은 여호와 하나님만이 참 하나님이심을 깨닫게 될 것입니다.', E'오늘의 핵심\n하나님께서는 교만한 애굽을 심판하시며 바벨론을 들어 사용하심으로써, 당신이 역사의 주관자이시며 온 세상의 참된 통치자이심을 만방에 나타내십니다.\n\n묵상 질문\n1. 애굽의 팔은 꺾이고 바벨론의 팔은 견고해지는 모습을 통해 하나님은 무엇을 가르치시나요?\n2. 내가 하나님보다 더 의지하고 있는 세상의 힘이나 우상은 무엇인가요?\n3. "내가 여호와인 줄 알리라"는 말씀이 오늘 나의 삶에 어떤 의미가 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-31', E'애굽에 대한 심판 (에스겔 31장)', E'에스겔 31장', E'한때 영광스러웠던 앗수르의 몰락을 통해 애굽의 운명을 예언하는 하나님의 말씀이 에스겔에게 임합니다. 하나님께서는 애굽의 바로에게 묻습니다. "네 큰 위엄을 누구에게 비하랴"(겔 31:2). 이어서 앗수르를 레바논의 백향목에 비유하며 그들의 과거 영광을 상세히 묘사하십니다. 풍부한 물로 자라나 하늘 높이 솟은 거대한 나무, 모든 새들이 깃들이고 모든 짐승이 그늘 아래 쉬며 열방이 그 아래 거하던 웅장한 나무의 모습은 한때 세계를 호령하던 앗수르 제국의 위용을 생생하게 보여줍니다.\n\n그러나 이 아름다운 나무는 교만으로 인해 무너집니다. 하나님의 동산 에덴의 모든 나무가 시기할 만큼 아름다웠던 그 나무는 자신의 높이와 영광을 스스로의 것으로 여기며 교만해졌습니다. 그 결과 하나님께서는 이방 민족의 손에 그들을 넘기셨고, 한때 세상을 지배하던 거대한 나무는 찍혀 쓰러졌습니다. 산과 골짜기에 가지가 흩어지고, 그 그늘 아래 있던 모든 이들이 떠나갔으며, 결국 스올로 내려가게 되었습니다.\n\n이 비유는 단순히 과거 앗수르의 이야기가 아닙니다. 하나님께서는 애굽의 바로에게 앗수르의 운명이 곧 애굽의 운명이 될 것임을 경고하고 계십니다. 나일 강의 풍요로움을 자랑하며 "나의 이 강은 내 것이라"고 외치던 애굽도 앗수르처럼 교만으로 인해 심판받을 것입니다. 하나님께서 주신 은혜와 번영을 자신의 공로로 돌리는 교만은 필연적으로 몰락을 가져옵니다. 물 가에 있는 모든 나무가 스스로 높아지지 못하게 하시는 이유는 모든 권세와 영광이 오직 하나님께로부터 온다는 진리를 깨닫게 하시기 위함입니다.', E'오늘의 핵심\n하나님께서는 앗수르의 흥망성쇠를 통해 애굽에게 경고하시며, 교만은 반드시 몰락으로 이어진다는 역사의 교훈을 가르치십니다.\n\n묵상 질문\n1. 내가 이룬 성취와 받은 축복을 누구의 것으로 여기고 있나요?\n2. 앗수르처럼 하나님의 은혜를 자신의 공로로 착각한 적은 없나요?\n3. 겸손히 하나님의 주권을 인정하며 살아가려면 어떤 노력이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-01', E'애굽에 대한 심판 (에스겔 32장)', E'에스겔 32장', E'에스겔 선지자는 애굽의 마지막 운명을 장송곡의 형태로 전달합니다. 이전까지 사자로 여겨졌던 애굽의 바로는 이제 "바다 가운데의 큰 악어"(겔 32:2)로 묘사되며, 그가 강물을 휘저어 더럽혔던 것처럼 하나님의 그물에 걸려 뭍으로 끌려 나올 것임을 보여줍니다. 애굽의 멸망은 단순한 한 나라의 패망을 넘어서 우주적 심판의 성격을 띱니다. 해와 달과 별들이 어두워지고 온 땅이 흑암으로 뒤덮이는 묘사는 창조 질서가 뒤집어지는 듯한 종말론적 심판을 연상시킵니다.\n\n본문의 후반부는 스올, 곧 음부에 내려간 열방들의 처참한 운명을 보여줍니다. 한때 세상을 두렵게 했던 앗수르, 엘람, 메섹과 두발, 에돔, 그리고 시돈까지 모두가 죽음의 구덩이에서 수치를 당하고 있습니다. 이들은 생전에 강대한 힘으로 다른 나라들을 위협했지만, 이제는 할례받지 못한 자들과 함께 누워 있을 뿐입니다. 특히 주목할 점은 하나님께서 바로에게 이러한 광경을 보여주시며 "위로를 받을 것"이라고 말씀하신다는 것입니다. 이는 애굽도 결국 다른 교만한 나라들과 같은 운명을 맞이할 것임을 암시합니다.\n\n이 엄중한 심판의 메시지는 단순히 고대 애굽만을 향한 것이 아닙니다. 하나님의 주권을 인정하지 않고 자신의 힘과 영광을 자랑하는 모든 세력에 대한 경고입니다. 나일강을 "내 것이라"고 주장했던 바로의 교만은 오늘날에도 하나님 없이 살아가려는 인간의 모습 속에서 반복됩니다. 그러나 역사의 주관자이신 하나님께서는 교만한 자를 낮추시고, 결국 모든 열방이 "내가 여호와인 줄" 알게 하실 것입니다. 이것이 심판 가운데서도 빛나는 하나님의 궁극적인 목적입니다.', E'오늘의 핵심\n하나님께서는 애굽과 열방의 심판을 통해 역사의 진정한 주관자가 누구인지를 분명히 드러내시며, 교만한 자들의 종말이 어떠한지를 엄중히 경고하십니다.\n\n묵상 질문\n1. 한때 강대했던 나라들이 모두 스올에 누워있는 모습을 통해 하나님은 무엇을 가르치시나요?\n2. 내 삶에서 "이것은 내 것이라"고 주장하며 하나님의 주권을 인정하지 않는 영역은 없나요?\n3. 심판의 메시지 속에서도 하나님을 알게 하시려는 그분의 마음을 어떻게 이해할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-03', E'예루살렘의 함락 (에스겔 33장)', E'에스겔 33장', E'포로로 끌려온 지 12년째, 예루살렘이 함락되었다는 소식이 에스겔에게 전해집니다. 도망친 자가 전한 이 비보는 포로민들에게 마지막 희망마저 무너뜨리는 절망의 선고였습니다. 하나님께서는 이러한 상황에서 에스겔을 다시 한번 이스라엘의 파수꾼으로 세우시며, 새로운 사명을 부여하십니다.\n\n파수꾼의 비유를 통해 하나님께서는 영적 지도자의 막중한 책임을 보여주십니다. 파수꾼이 위험을 보고도 나팔을 불지 않으면 백성의 피를 그의 손에서 찾겠다는 엄중한 경고는, 하나님의 말씀을 전하는 자의 사명이 얼마나 절박한지를 일깨워줍니다. 에스겔은 악인에게 경고하여 돌이키게 하는 것이 자신의 생명을 보전하는 길임을 깨닫게 됩니다.\n\n그러나 하나님의 마음은 심판 자체에 있지 않습니다. "나는 악인이 죽는 것을 기뻐하지 아니하고 악인이 그의 길에서 돌이켜 떠나 사는 것을 기뻐하노라"(겔 33:11)는 말씀은 하나님의 본심을 드러냅니다. 죄악으로 인해 쇠퇴하는 백성들의 절망적인 탄식에도 불구하고, 하나님께서는 여전히 돌이킬 기회를 주시며 생명의 길로 초청하고 계신 것입니다.\n\n예루살렘에 남아있던 자들은 오히려 교만하게도 아브라함의 예를 들며 땅의 소유권을 주장합니다. 그들은 우상숭배와 살인, 간음 등 온갖 죄악을 행하면서도 하나님의 약속을 자신들의 것으로 여겼습니다. 이에 하나님께서는 그들의 교만을 꺾으시고 땅을 황무지로 만들 것을 선언하십니다.\n\n한편 포로민들은 에스겔의 설교를 듣기 위해 모여들지만, 마치 음악을 감상하듯 귀로만 듣고 마음으로는 받아들이지 않습니다. 그들은 입으로는 사랑을 나타내지만 마음으로는 여전히 이익을 따르고 있었습니다. 그러나 하나님께서는 말씀이 반드시 이루어질 때 그들이 참 선지자가 자기들 가운데 있었음을 알게 될 것이라고 말씀하십니다.', E'오늘의 핵심\n예루살렘이 함락된 절망적 상황에서도 하나님께서는 여전히 회개와 생명의 길을 제시하시며, 파수꾼된 자들에게 그 메시지를 전할 책임을 부여하십니다.\n\n묵상 질문\n1. 나는 주변 사람들에게 하나님의 경고와 사랑을 전하는 영적 파수꾼의 역할을 감당하고 있나요?\n2. 하나님의 말씀을 단순히 듣기 좋은 소리로만 여기고 실천하지 않는 모습은 없나요?\n3. 절망적인 상황에서도 악인의 회개를 기뻐하시는 하나님의 마음을 어떻게 나눌 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-04', E'예루살렘의 함락 (에스겔 34장)', E'에스겔 34장', E'이스라엘의 목자들을 향한 하나님의 준엄한 심판이 선포됩니다. 에스겔을 통해 전해지는 메시지는 양 떼를 돌보아야 할 목자들이 오히려 양들을 착취하고 자기 배만 불리는 타락한 현실을 고발합니다. 목자들은 살진 양을 잡아먹고 그 털로 옷을 해 입으면서도 정작 양 떼는 돌보지 않았습니다. 연약한 자를 강하게 하지 않고, 병든 자를 고치지 않으며, 상한 자를 싸매주지 않았습니다. 흩어진 자를 찾지도 않고 오직 포악으로 다스렸던 것입니다.\n\n목자를 잃은 양들은 산과 들에 흩어져 들짐승의 밥이 되었습니다. 이러한 비극적 상황에 하나님께서 직접 개입하십니다. "내가 친히 내 양의 목자가 되어"(겔 34:15)라는 선언은 실패한 인간 지도자들을 대신하여 하나님께서 직접 목자가 되시겠다는 약속입니다. 하나님은 흩어진 양을 찾아 모으시고, 좋은 꼴을 먹이시며, 상한 자를 싸매주고 병든 자를 강하게 하실 것입니다.\n\n더 나아가 하나님은 "내 종 다윗"을 세워 참된 목자가 되게 하시겠다고 약속하십니다. 이는 단순히 과거 다윗 왕조의 회복이 아니라, 다윗의 후손으로 오실 메시아를 가리키는 예언입니다. 그 목자 아래에서 이스라엘은 화평의 언약을 누리며, 악한 짐승의 위협 없이 평안히 거하게 될 것입니다. 때를 따라 내리는 복된 소낙비와 풍성한 열매, 그리고 "나는 너희 하나님이라"는 언약의 회복이 약속됩니다.\n\n이스라엘의 실패한 지도자들에 대한 심판 선언은 동시에 하나님의 신실한 돌보심에 대한 약속이기도 합니다. 인간 지도자의 실패가 하나님의 계획을 좌절시킬 수 없으며, 오히려 하나님께서 친히 목자가 되어 주심으로써 더 완전한 구원이 이루어질 것을 보여줍니다.', E'오늘의 핵심\n실패한 목자들을 심판하시는 하나님은 친히 참 목자가 되어 흩어진 양 떼를 모으시고, 메시아를 통한 완전한 회복을 약속하십니다.\n\n묵상 질문\n1. 내게 맡겨진 영혼들을 섬기는 일에 있어서 자기 유익을 먼저 구하지는 않았나요?\n2. 하나님께서 친히 목자가 되신다는 약속이 오늘 나에게 주는 위로는 무엇인가요?\n3. 연약한 자를 돌보고 흩어진 자를 찾는 일에 나는 어떻게 동참할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-05', E'예루살렘의 함락 (에스겔 35장)', E'에스겔 35장', E'에돔은 이스라엘과 뿌리를 같이하는 형제의 나라였습니다. 야곱의 형 에서의 후손들이 세운 나라가 바로 에돔이었기 때문입니다. 그러나 이들은 역사 속에서 끊임없이 갈등하며 대립해왔습니다. 특히 B.C. 586년 바벨론이 예루살렘을 파괴할 때, 에돔은 형제의 고난을 기회로 삼아 칼을 들었습니다. 하나님께서는 에스겔을 통해 세일 산, 곧 에돔을 향한 심판의 메시지를 선포하십니다.\n\n에돔의 죄는 단순한 적대 행위를 넘어선 것이었습니다. 그들은 "옛날부터 한을 품고" 이스라엘의 환난을 자신들의 이익을 위한 기회로 삼았습니다. 형제가 어려움에 처했을 때 도움의 손길을 내밀기는커녕, 오히려 그들의 고통에 편승하여 약탈과 살육에 가담했던 것입니다. 더욱이 에돔은 "이 두 민족과 두 땅은 다 내 것이며 내 기업이 되리라"고 교만하게 선언했습니다. 이는 하나님의 백성과 그들의 기업을 탐낸 것일 뿐 아니라, 그 땅에 계신 하나님의 주권을 무시한 행위였습니다.\n\n하나님께서는 에돔의 이러한 행악에 대해 철저한 심판을 선포하십니다. 세일 산은 황무지가 되고, 그 성읍들은 영원히 폐허가 되어 다시는 거주하는 자가 없을 것입니다. 특히 주목할 점은 하나님께서 "네가 피를 미워하지 아니하였은즉 피가 너를 따르리라"고 말씀하신 부분입니다. 피를 흘리기를 즐겼던 에돔은 그들이 뿌린 대로 거두게 될 것입니다.\n\n이 심판의 말씀은 단지 에돔만을 위한 것이 아닙니다. 형제의 고난을 기뻐하고, 약자의 어려움을 기회로 삼으며, 하나님의 주권을 무시하는 모든 이들을 향한 경고입니다. 하나님께서는 당신의 백성을 괴롭히고 조롱하는 자들을 결코 그냥 두지 않으십니다. "내가 여호와인 줄을 너희가 알리라"는 선언은 역사의 주권자이신 하나님의 확고한 의지를 보여줍니다.', E'오늘의 핵심\n하나님께서는 형제의 고난을 기회로 삼아 악을 행한 에돔을 심판하시며, 역사의 주권자로서 당신의 백성을 지키시는 분임을 선포하십니다.\n\n묵상 질문\n1. 타인의 어려움을 나의 이익을 위한 기회로 삼은 적은 없나요?\n2. 형제를 향한 미움과 질투가 내 마음속에 자리 잡고 있지는 않나요?\n3. 하나님의 주권을 인정하며 이웃을 사랑하기 위해 오늘 무엇을 실천하겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-06', E'다시 회복될 이스라엘 (에스겔 36장)', E'에스겔 36장', E'포로로 끌려간 이스라엘 백성에게 하나님께서는 에스겔을 통해 놀라운 회복의 메시지를 전하십니다. 36장은 특별히 이스라엘의 산들을 향한 예언으로 시작됩니다. 황폐해진 이스라엘 땅이 주변 이방 나라들의 조롱거리가 되었지만, 하나님께서는 그 땅을 다시 회복시키실 것을 약속하십니다. \n\n하나님의 회복 계획에는 분명한 이유가 있었습니다. 이스라엘이 우상숭배와 불의로 땅을 더럽혔고, 그 결과 여러 나라로 흩어졌을 때, 이방인들은 "이들은 여호와의 백성이라도 여호와의 땅에서 떠난 자라"(겔 36:20)고 조롱했습니다. 하나님의 거룩한 이름이 이스라엘로 인해 더럽혀진 것입니다. 그래서 하나님께서는 자신의 거룩한 이름을 위하여 이스라엘을 회복시키기로 작정하셨습니다.\n\n이 회복의 약속은 단순히 고국으로의 귀환만을 의미하지 않습니다. 하나님께서는 맑은 물로 그들을 정결케 하시고, 돌같이 굳은 마음을 제거하여 부드러운 마음을 주시며, 새 영을 그들 속에 두어 하나님의 율례를 행하게 하실 것을 약속하십니다. 이는 외적인 회복을 넘어선 영적인 갱신의 약속입니다.\n\n특별히 주목할 것은 이 모든 회복이 이스라엘의 공로나 자격 때문이 아니라는 점입니다. 하나님께서는 두 번이나 "내가 이렇게 행함은 너희를 위함이 아니"라고 강조하십니다. 오히려 이스라엘은 자신들의 악한 행위를 기억하고 부끄러워해야 할 처지였습니다. 그럼에도 하나님께서는 자신의 거룩한 이름을 위하여, 그리고 언약에 신실하신 사랑 때문에 그들을 회복시키시는 것입니다. 황폐했던 땅이 에덴동산 같이 될 것이며, 이를 본 주변 나라들이 여호와께서 행하신 일임을 알게 될 것입니다.', E'오늘의 핵심\n하나님께서는 자신의 거룩한 이름을 위하여 이스라엘을 회복시키시며, 그들에게 새 마음과 새 영을 주어 진정한 영적 갱신을 이루실 것을 약속하십니다.\n\n묵상 질문\n1. 하나님께서 나를 회복시키시는 이유가 내 자격 때문이 아니라 그분의 은혜라는 것을 깨닫고 있나요?\n2. 내 삶에서 돌같이 굳은 마음을 부드럽게 바꾸어 달라고 기도해야 할 영역은 무엇인가요?\n3. 하나님의 이름이 내 삶을 통해 거룩히 여김을 받고 있나요, 아니면 오히려 욕을 받고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-07', E'다시 회복될 이스라엘 (에스겔 37장)', E'에스겔 37장', E'바벨론 포로기의 절망적인 현실 속에서 하나님은 에스겔에게 놀라운 환상을 보여주십니다. 하나님의 영이 에스겔을 데려간 곳은 마른 뼈들로 가득한 골짜기였습니다. 그 뼈들은 너무나 메말라 있어서 생명의 흔적이라곤 전혀 찾아볼 수 없었습니다. 이는 바로 당시 이스라엘 백성들의 영적 상태를 보여주는 것이었습니다. 나라는 멸망했고, 성전은 파괴되었으며, 백성들은 이방 땅에 흩어져 있었습니다. 그들의 입에서는 "우리의 뼈들이 말랐고 우리의 소망이 없어졌으니 우리는 다 멸절되었다"(겔 37:11)라는 절망의 탄식이 흘러나왔습니다.\n\n그러나 하나님은 이 죽음의 골짜기에서 생명의 역사를 일으키십니다. 에스겔이 하나님의 명령대로 대언하자 놀라운 일이 일어났습니다. 먼저 뼈들이 서로 연결되고, 힘줄이 생기며, 살이 오르고, 가죽이 덮였습니다. 그리고 마침내 하나님의 생기가 그들에게 들어가자 그들은 살아나서 극히 큰 군대가 되었습니다. 이 환상은 단순히 육체적 부활만을 의미하는 것이 아닙니다. 하나님께서 절망에 빠진 이스라엘을 영적으로 회복시키시고, 그들을 다시 하나님의 백성으로 세우실 것을 보여주는 것입니다.\n\n더 나아가 하나님은 두 막대기의 환상을 통해 분열되었던 남북 이스라엘이 하나로 통일될 것을 약속하십니다. 유다와 에브라임으로 나뉘어졌던 백성이 다시 한 나라가 되고, 한 왕의 통치를 받게 될 것입니다. 그 왕은 다윗의 계보를 잇는 메시아적 왕으로, 백성들을 하나님의 규례대로 인도할 것입니다. 하나님의 성소가 그들 가운데 영원히 거하며, 화평의 언약이 영원한 언약으로 세워질 것입니다. 이것이 절망 중에 있는 백성에게 주시는 하나님의 회복의 약속이었습니다.', E'오늘의 핵심\n마른 뼈처럼 완전히 죽어있던 이스라엘에게 하나님은 생명의 영을 불어넣으시어 다시 살리시고, 분열된 백성을 하나로 만드시며 영원한 언약 관계를 회복시켜 주십니다.\n\n묵상 질문\n1. 내 삶의 어떤 영역이 마른 뼈처럼 메말라 있으며, 하나님의 생기가 필요한가요?\n2. 하나님께서는 절망적인 상황에서도 회복의 소망을 주시는 분임을 믿고 있나요?\n3. 분열과 갈등으로 아픈 공동체를 위해 하나님의 치유와 연합을 구하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-08', E'침략자 곡에 대한 심판과 멸망 (에스겔 38장)', E'에스겔 38장', E'에스겔 38장은 마곡 땅의 곡에 대한 심판 예언을 담고 있습니다. 바벨론 포로기의 어둠 속에서 하나님께서는 이스라엘의 대적들이 어떻게 심판받을 것인지를 미리 보여주심으로써 당신의 백성에게 소망을 주고 계십니다. 곡은 로스와 메섹과 두발의 왕으로, 북방에서 거대한 연합군을 이끌고 이스라엘을 침략하려는 자로 묘사됩니다. 그는 바사와 구스와 붓, 고멜과 도갈마 족속까지 규합하여 "구름 같이 땅을 덮으리라"(겔 38:9)고 표현될 만큼 압도적인 군세를 자랑합니다.\n\n그러나 하나님께서는 이 모든 계획을 이미 아시고 계셨습니다. 곡이 평안히 거주하는 이스라엘 백성을 노략하려는 악한 꾀를 품고 있음을 아시고, 오히려 그를 끌어내어 당신의 거룩하심을 나타내는 도구로 사용하시려는 것입니다. 하나님께서는 곡의 침략을 허락하시되, 그것이 바로 심판의 때가 될 것임을 선언하십니다. 큰 지진과 전염병, 폭우와 우박, 불과 유황으로 곡과 그의 모든 군대를 심판하실 것입니다. \n\n이 예언의 궁극적인 목적은 단순한 심판이 아닙니다. 하나님께서는 "내가 너로 말미암아 이방 사람의 눈 앞에서 내 거룩함을 나타내어 그들이 다 나를 알게 하려 함이라"고 말씀하십니다. 곡의 멸망을 통해 열방이 여호와 하나님을 알게 되리라는 것입니다. 포로 생활의 고통 속에서 신음하던 이스라엘 백성에게 이 예언은 하나님께서 여전히 역사의 주관자이시며, 당신의 백성을 잊지 않으셨다는 확신을 주었을 것입니다. 악이 승리하는 것처럼 보이는 순간에도 하나님의 주권적인 통치는 계속되고 있음을 보여줍니다.', E'오늘의 핵심\n하나님께서는 곡의 침략 계획을 미리 아시고 오히려 그것을 통해 당신의 거룩하심을 만방에 나타내시며, 포로 된 백성에게는 하나님이 여전히 역사의 주관자이심을 확신시켜 주십니다.\n\n묵상 질문\n1. 악이 득세하는 것 같은 현실 속에서도 하나님의 주권을 신뢰하고 있나요?\n2. 하나님께서 나의 어려움을 통해서도 당신의 영광을 나타내실 수 있음을 믿으시나요?\n3. 오늘 내가 평안히 거하는 것이 하나님의 보호하심 때문임을 감사하고 있나요?');
